// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const bankBmProfessionalQuestions: Question[] = [
  { id: 'bank-bm-prof-1', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-branch-operations', type: 'multiple-choice', content: { es: 'Durante el arqueo de cierre, se detecta un faltante de USD 2,000 en la bóveda de la sucursal. El sistema muestra todas las transacciones cuadradas. ¿Cuál es el procedimiento correcto a seguir?', en: 'During the closing cash count, a USD 2,000 shortage is detected in the branch vault. The system shows all transactions balanced. What is the correct procedure to follow?', fr: 'Lors du comptage de fermeture, un manque de 2 000 USD est détecté dans le coffre de l\'agence. Le système montre toutes les transactions équilibrées. Quelle est la procédure correcte à suivre ?' }, options: [{ id: 'a', text: { es: 'Reponer el faltante con fondos personales para evitar reportarlo', en: 'Replace the shortage with personal funds to avoid reporting it', fr: 'Remplacer le manque avec des fonds personnels pour éviter de le signaler' }, value: 0 }, { id: 'b', text: { es: 'Documentar la diferencia, revisar las grabaciones de seguridad, verificar cada transacción del día y reportar al área de control interno según el protocolo establecido', en: 'Document the difference, review security footage, verify each transaction of the day, and report to internal control per established protocol', fr: 'Documenter la différence, examiner les enregistrements de sécurité, vérifier chaque transaction du jour et signaler au contrôle interne selon le protocole établi' }, value: 100 }, { id: 'c', text: { es: 'Esperar al día siguiente para ver si el error se corrige solo', en: 'Wait until the next day to see if the error corrects itself', fr: 'Attendre le lendemain pour voir si l\'erreur se corrige d\'elle-même' }, value: 0 }, { id: 'd', text: { es: 'Registrar la diferencia como un gasto operativo menor de la sucursal', en: 'Record the difference as a minor operational expense of the branch', fr: 'Enregistrer la différence comme une dépense opérationnelle mineure de l\'agence' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bm-prof-2', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-commercial-mgmt', type: 'multiple-choice', content: { es: 'Su sucursal está al 60% de la meta trimestral de colocación de créditos de consumo faltando un mes. El equipo tiene 8 asesores. ¿Qué estrategia comercial implementaría?', en: 'Your branch is at 60% of the quarterly consumer loan placement target with one month remaining. The team has 8 advisors. What commercial strategy would you implement?', fr: 'Votre agence est à 60% de l\'objectif trimestriel de placement de crédits à la consommation avec un mois restant. L\'équipe compte 8 conseillers. Quelle stratégie commerciale mettriez-vous en place ?' }, options: [{ id: 'a', text: { es: 'Analizar la cartera de clientes existentes para identificar oportunidades de cross-selling, asignar metas individuales diferenciadas por fortaleza de cada asesor y lanzar campañas de pre-aprobación dirigidas', en: 'Analyze the existing client portfolio for cross-selling opportunities, assign differentiated individual targets based on each advisor\'s strengths, and launch targeted pre-approval campaigns', fr: 'Analyser le portefeuille clients existants pour des opportunités de ventes croisées, assigner des objectifs individuels différenciés selon les forces de chaque conseiller et lancer des campagnes de pré-approbation ciblées' }, value: 100 }, { id: 'b', text: { es: 'Presionar al equipo con reuniones diarias de seguimiento hasta alcanzar la meta', en: 'Pressure the team with daily follow-up meetings until the target is met', fr: 'Faire pression sur l\'équipe avec des réunions quotidiennes de suivi jusqu\'à atteindre l\'objectif' }, value: 25 }, { id: 'c', text: { es: 'Solicitar a la gerencia regional que reduzca la meta de la sucursal', en: 'Ask regional management to reduce the branch target', fr: 'Demander à la direction régionale de réduire l\'objectif de l\'agence' }, value: 0 }, { id: 'd', text: { es: 'Ofrecer tasas preferenciales no autorizadas para atraer más clientes', en: 'Offer unauthorized preferential rates to attract more clients', fr: 'Offrir des taux préférentiels non autorisés pour attirer plus de clients' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bm-prof-3', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-regulatory', type: 'multiple-choice', content: { es: 'Un cliente frecuente y de alto valor realiza tres depósitos en efectivo de USD 9,500 cada uno en días consecutivos. ¿Qué acción toma usted como gerente?', en: 'A frequent, high-value client makes three cash deposits of USD 9,500 each on consecutive days. What action do you take as branch manager?', fr: 'Un client fréquent et de grande valeur effectue trois dépôts en espèces de 9 500 USD chacun sur des jours consécutifs. Quelle action prenez-vous en tant que directeur ?' }, options: [{ id: 'a', text: { es: 'No hacer nada ya que cada depósito está por debajo del umbral de reporte', en: 'Do nothing since each deposit is below the reporting threshold', fr: 'Ne rien faire car chaque dépôt est en dessous du seuil de signalement' }, value: 0 }, { id: 'b', text: { es: 'Generar un Reporte de Operación Sospechosa (ROS) por posible estructuración (smurfing) y notificar al oficial de cumplimiento, sin alertar al cliente', en: 'Generate a Suspicious Activity Report (SAR) for possible structuring (smurfing) and notify the compliance officer, without alerting the client', fr: 'Générer un Rapport d\'Opération Suspecte pour structuration possible (schtroumpfage) et notifier le responsable de conformité, sans alerter le client' }, value: 100 }, { id: 'c', text: { es: 'Preguntarle al cliente por qué divide sus depósitos', en: 'Ask the client why they are splitting their deposits', fr: 'Demander au client pourquoi il divise ses dépôts' }, value: 25 }, { id: 'd', text: { es: 'Rechazar los depósitos futuros del cliente', en: 'Reject the client\'s future deposits', fr: 'Refuser les dépôts futurs du client' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bm-prof-4', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-branch-operations', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene supervisando las operaciones diarias de una sucursal bancaria (apertura/cierre, arqueos, gestión de bóveda, cuadres)?', en: 'What level of experience do you have supervising daily bank branch operations (opening/closing, cash counts, vault management, balancing)?', fr: 'Quel niveau d\'expérience avez-vous dans la supervision des opérations quotidiennes d\'une agence bancaire (ouverture/fermeture, comptages, gestion du coffre, équilibrage) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Sin experiencia en gestión operativa de sucursal', en: 'No experience in branch operations management', fr: 'Aucune expérience en gestion opérationnelle d\'agence' }, max: { es: 'Amplia experiencia gestionando operaciones de múltiples sucursales', en: 'Extensive experience managing multi-branch operations', fr: 'Vaste expérience dans la gestion des opérations de plusieurs agences' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bm-prof-5', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-commercial-mgmt', type: 'scenario', content: { es: 'La sucursal que usted dirige está ubicada en una zona comercial donde acaban de abrir dos sucursales de bancos competidores con ofertas agresivas de captación (tasas de ahorro un 2% superiores a las suyas). En los últimos 3 meses ha perdido el 12% de sus depósitos a plazo fijo. Su presupuesto de marketing local es limitado y no puede igualar las tasas de la competencia.\n\nDescriba su plan integral para retener clientes existentes, recuperar los perdidos y captar nuevos, considerando que no puede competir únicamente por tasa.', en: 'The branch you manage is located in a commercial area where two competitor bank branches have just opened with aggressive deposit offers (savings rates 2% higher than yours). In the last 3 months you have lost 12% of your fixed-term deposits. Your local marketing budget is limited and you cannot match competitor rates.\n\nDescribe your comprehensive plan to retain existing clients, recover lost ones, and acquire new ones, considering you cannot compete on rate alone.', fr: 'L\'agence que vous dirigez est située dans une zone commerciale où deux agences de banques concurrentes viennent d\'ouvrir avec des offres agressives de captation (taux d\'épargne supérieurs de 2% aux vôtres). Vous avez perdu 12% de vos dépôts à terme fixe en 3 mois. Votre budget marketing local est limité.\n\nDécrivez votre plan intégral pour fidéliser les clients existants, récupérer les perdus et en acquérir de nouveaux.' }, rubric: { es: 'Evaluar: (1) Estrategia de retención basada en valor agregado y relación personalizada, (2) Segmentación de clientes y priorización de esfuerzos, (3) Ofertas de productos combinados (bundling) que compensen la diferencia de tasa, (4) Alianzas comerciales locales y presencia comunitaria, (5) Uso de canales digitales y referidos, (6) Métricas de seguimiento y ajuste.', en: 'Evaluate: (1) Retention strategy based on added value and personalized relationship, (2) Client segmentation and effort prioritization, (3) Bundled product offers to offset rate differential, (4) Local commercial partnerships and community presence, (5) Digital channel and referral usage, (6) Tracking metrics and adjustment.', fr: 'Évaluer : (1) Stratégie de fidélisation basée sur la valeur ajoutée, (2) Segmentation des clients, (3) Offres de produits combinés, (4) Partenariats commerciaux locaux, (5) Utilisation des canaux numériques, (6) Métriques de suivi.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-bm-prof-6', profileId: 'bank-branch-manager', categoryId: 'bank-bm-professional', competencyId: 'bank-bm-regulatory', type: 'open-text', content: { es: 'Describa cómo implementaría un programa integral de cumplimiento de Prevención de Lavado de Dinero (PLD/AML) en su sucursal, incluyendo capacitación del personal, monitoreo de transacciones y cultura de cumplimiento.', en: 'Describe how you would implement a comprehensive Anti-Money Laundering (AML) compliance program in your branch, including staff training, transaction monitoring, and compliance culture.', fr: 'Décrivez comment vous mettriez en place un programme complet de conformité en matière de Lutte contre le Blanchiment d\'Argent (LCB) dans votre agence, incluant la formation du personnel, le suivi des transactions et la culture de conformité.' }, rubric: { es: 'Evaluar: (1) Programa de capacitación periódica y certificación en PLD, (2) Sistemas de monitoreo de transacciones y alertas, (3) Procedimientos de Conozca a su Cliente (KYC) y debida diligencia reforzada, (4) Cultura de reporte sin represalias, (5) Coordinación con el oficial de cumplimiento, (6) Documentación y auditoría interna.', en: 'Evaluate: (1) Periodic AML training and certification program, (2) Transaction monitoring systems and alerts, (3) KYC procedures and enhanced due diligence, (4) Whistleblowing culture without retaliation, (5) Coordination with compliance officer, (6) Documentation and internal audit.', fr: 'Évaluer : (1) Programme de formation périodique en LCB, (2) Systèmes de surveillance des transactions, (3) Procédures KYC et diligence renforcée, (4) Culture de signalement, (5) Coordination avec le responsable conformité, (6) Documentation et audit interne.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (2 multiple-choice + 2 scale + 1 ranking + 1 open-text) ---
export const bankBmSoftSkillsQuestions: Question[] = [
  { id: 'bank-bm-ss-1', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-leadership', type: 'multiple-choice', content: { es: 'Uno de sus mejores asesores comerciales ha bajado su rendimiento significativamente en las últimas semanas. Al conversar con él, descubre que tiene problemas personales que le afectan. ¿Cómo maneja la situación?', en: 'One of your best commercial advisors has significantly decreased their performance in recent weeks. Upon talking with them, you discover personal problems are affecting them. How do you handle the situation?', fr: 'L\'un de vos meilleurs conseillers commerciaux a considérablement baissé en performance ces dernières semaines. En discutant avec lui, vous découvrez que des problèmes personnels l\'affectent. Comment gérez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Escuchar con empatía, ofrecer flexibilidad temporal en su carga de trabajo, conectarlo con programas de asistencia al empleado y establecer un plan de recuperación gradual con seguimiento', en: 'Listen empathetically, offer temporary flexibility in workload, connect them with employee assistance programs, and establish a gradual recovery plan with follow-up', fr: 'Écouter avec empathie, offrir une flexibilité temporaire dans la charge de travail, le connecter aux programmes d\'aide aux employés et établir un plan de rétablissement progressif avec suivi' }, value: 100 }, { id: 'b', text: { es: 'Decirle que los problemas personales no deben afectar el trabajo y exigir que recupere su rendimiento', en: 'Tell them personal problems should not affect work and demand they recover their performance', fr: 'Lui dire que les problèmes personnels ne doivent pas affecter le travail et exiger qu\'il retrouve sa performance' }, value: 0 }, { id: 'c', text: { es: 'Ignorar la situación y esperar que se resuelva sola', en: 'Ignore the situation and wait for it to resolve itself', fr: 'Ignorer la situation et attendre qu\'elle se résolve d\'elle-même' }, value: 0 }, { id: 'd', text: { es: 'Redistribuir inmediatamente sus clientes a otros asesores', en: 'Immediately redistribute their clients to other advisors', fr: 'Redistribuer immédiatement ses clients à d\'autres conseillers' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bm-ss-2', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-client-relationship', type: 'multiple-choice', content: { es: 'Un cliente empresarial importante llega furioso a la sucursal porque un error del sistema provocó que se duplicara un cobro de USD 50,000 en su cuenta. El equipo aún no puede revertir la transacción. ¿Qué hace primero?', en: 'An important corporate client arrives at the branch furious because a system error caused a duplicate charge of USD 50,000 in their account. The team cannot yet reverse the transaction. What do you do first?', fr: 'Un client entreprise important arrive furieux à l\'agence car une erreur système a provoqué un double prélèvement de 50 000 USD sur son compte. L\'équipe ne peut pas encore annuler la transaction. Que faites-vous en premier ?' }, options: [{ id: 'a', text: { es: 'Atenderlo personalmente, reconocer el error, explicar los pasos exactos y tiempos para la resolución, ofrecer una solución temporal (línea de crédito o facilidad) y hacer seguimiento personal hasta la resolución', en: 'Attend to them personally, acknowledge the error, explain the exact steps and timeline for resolution, offer a temporary solution (credit line or facility), and personally follow up until resolution', fr: 'Le recevoir personnellement, reconnaître l\'erreur, expliquer les étapes exactes et les délais de résolution, offrir une solution temporaire et assurer un suivi personnel jusqu\'à la résolution' }, value: 100 }, { id: 'b', text: { es: 'Derivarlo al área de servicio al cliente para que gestionen el reclamo', en: 'Refer them to the customer service area to handle the claim', fr: 'Le diriger vers le service client pour gérer la réclamation' }, value: 25 }, { id: 'c', text: { es: 'Explicarle que es un error del sistema y que se resolverá cuando el área técnica lo corrija', en: 'Explain it\'s a system error and it will be resolved when the technical area fixes it', fr: 'Expliquer que c\'est une erreur système qui sera résolue quand l\'équipe technique la corrigera' }, value: 25 }, { id: 'd', text: { es: 'Pedirle que envíe un reclamo formal por escrito', en: 'Ask them to submit a formal written complaint', fr: 'Lui demander de soumettre une réclamation formelle par écrit' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bm-ss-3', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-leadership', type: 'scale', content: { es: '¿Cómo califica su capacidad para motivar y desarrollar equipos de trabajo en un entorno de metas comerciales exigentes?', en: 'How do you rate your ability to motivate and develop work teams in a demanding commercial target environment?', fr: 'Comment évaluez-vous votre capacité à motiver et développer des équipes de travail dans un environnement d\'objectifs commerciaux exigeants ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Poca experiencia liderando equipos comerciales', en: 'Little experience leading commercial teams', fr: 'Peu d\'expérience dans la direction d\'équipes commerciales' }, max: { es: 'Líder experimentado con equipos de alto rendimiento', en: 'Experienced leader with high-performance teams', fr: 'Leader expérimenté avec des équipes de haute performance' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bm-ss-4', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-conflict-resolution', type: 'scale', content: { es: '¿Qué tan efectivo se considera al mediar y resolver conflictos entre miembros del equipo o con clientes insatisfechos?', en: 'How effective do you consider yourself at mediating and resolving conflicts between team members or with dissatisfied clients?', fr: 'À quel point vous considérez-vous efficace pour médier et résoudre les conflits entre membres de l\'équipe ou avec des clients insatisfaits ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Tiendo a evitar los conflictos', en: 'I tend to avoid conflicts', fr: 'J\'ai tendance à éviter les conflits' }, max: { es: 'Resuelvo conflictos de forma proactiva logrando acuerdos satisfactorios', en: 'I resolve conflicts proactively achieving satisfactory agreements', fr: 'Je résous les conflits de manière proactive en obtenant des accords satisfaisants' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bm-ss-5', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-client-relationship', type: 'ranking', content: { es: 'Ordene las siguientes acciones por importancia al construir relaciones duraderas con clientes clave de la sucursal:', en: 'Rank the following actions by importance when building lasting relationships with key branch clients:', fr: 'Classez les actions suivantes par importance pour construire des relations durables avec les clients clés de l\'agence :' }, options: [{ id: 'a', text: { es: 'Conocer personalmente sus necesidades financieras y metas de negocio', en: 'Personally understand their financial needs and business goals', fr: 'Connaître personnellement leurs besoins financiers et objectifs commerciaux' }, value: 1 }, { id: 'b', text: { es: 'Ofrecer proactivamente productos y servicios relevantes', en: 'Proactively offer relevant products and services', fr: 'Offrir proactivement des produits et services pertinents' }, value: 2 }, { id: 'c', text: { es: 'Dar seguimiento oportuno a cada solicitud y compromiso', en: 'Provide timely follow-up on every request and commitment', fr: 'Assurer un suivi opportun de chaque demande et engagement' }, value: 3 }, { id: 'd', text: { es: 'Resolver problemas rápidamente cuando surgen', en: 'Resolve problems quickly when they arise', fr: 'Résoudre les problèmes rapidement quand ils surviennent' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'bank-bm-ss-6', profileId: 'bank-branch-manager', categoryId: 'bank-bm-soft-skills', competencyId: 'bank-bm-conflict-resolution', type: 'open-text', content: { es: 'Describa una situación en la que tuvo que mediar un conflicto significativo dentro de su equipo de trabajo. ¿Cuál era el conflicto, cómo lo abordó y cuál fue el resultado?', en: 'Describe a situation where you had to mediate a significant conflict within your work team. What was the conflict, how did you approach it, and what was the outcome?', fr: 'Décrivez une situation où vous avez dû médier un conflit significatif au sein de votre équipe de travail. Quel était le conflit, comment l\'avez-vous abordé et quel a été le résultat ?' }, rubric: { es: 'Evaluar: (1) Identificación clara del conflicto y partes involucradas, (2) Escucha activa e imparcialidad, (3) Enfoque en intereses vs. posiciones, (4) Solución constructiva y aceptada, (5) Prevención de recurrencia, (6) Impacto positivo en el equipo.', en: 'Evaluate: (1) Clear identification of conflict and parties involved, (2) Active listening and impartiality, (3) Focus on interests vs. positions, (4) Constructive and accepted solution, (5) Prevention of recurrence, (6) Positive team impact.', fr: 'Évaluer : (1) Identification claire du conflit, (2) Écoute active et impartialité, (3) Focus sur les intérêts vs positions, (4) Solution constructive, (5) Prévention de récurrence, (6) Impact positif sur l\'équipe.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (2 multiple-choice + 2 scale + 1 scenario + 1 open-text) ---
export const bankBmReadinessQuestions: Question[] = [
  { id: 'bank-bm-rd-1', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-digital-transformation', type: 'multiple-choice', content: { es: 'La casa matriz anuncia que el 40% de las transacciones de ventanilla deben migrar a canales digitales en 12 meses. Parte de su equipo teme perder relevancia. ¿Cuál es su enfoque?', en: 'Headquarters announces that 40% of counter transactions must migrate to digital channels within 12 months. Part of your team fears losing relevance. What is your approach?', fr: 'Le siège annonce que 40% des transactions au guichet doivent migrer vers les canaux numériques en 12 mois. Une partie de votre équipe craint de perdre sa pertinence. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Capacitar al equipo en asesoría consultiva, posicionar la migración como una oportunidad de crecimiento profesional, establecer embajadores digitales y rediseñar roles hacia funciones de mayor valor', en: 'Train the team in consultative advisory, position the migration as a professional growth opportunity, establish digital ambassadors, and redesign roles toward higher-value functions', fr: 'Former l\'équipe au conseil consultatif, positionner la migration comme une opportunité de croissance professionnelle, établir des ambassadeurs numériques et redéfinir les rôles vers des fonctions à plus forte valeur' }, value: 100 }, { id: 'b', text: { es: 'Implementar la migración y reducir personal gradualmente', en: 'Implement the migration and gradually reduce staff', fr: 'Mettre en œuvre la migration et réduire progressivement le personnel' }, value: 25 }, { id: 'c', text: { es: 'Resistir la directiva argumentando que los clientes de la zona prefieren atención presencial', en: 'Resist the directive arguing that clients in the area prefer in-person service', fr: 'Résister à la directive en argumentant que les clients de la zone préfèrent le service en personne' }, value: 0 }, { id: 'd', text: { es: 'Cumplir con el porcentaje exigido sin preocuparse por la experiencia del cliente', en: 'Meet the required percentage without worrying about customer experience', fr: 'Atteindre le pourcentage requis sans se soucier de l\'expérience client' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bm-rd-2', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-change-management', type: 'multiple-choice', content: { es: 'Se implementa un nuevo sistema core bancario que cambia radicalmente los procesos de la sucursal. El 60% del equipo se resiste al cambio. ¿Qué hace?', en: 'A new core banking system is implemented that radically changes branch processes. 60% of the team resists the change. What do you do?', fr: 'Un nouveau système bancaire central est mis en place qui change radicalement les processus de l\'agence. 60% de l\'équipe résiste au changement. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Identificar campeones del cambio dentro del equipo, organizar sesiones de práctica graduales, reconocer avances, crear un canal de retroalimentación y demostrar personalmente el uso del nuevo sistema', en: 'Identify change champions within the team, organize gradual practice sessions, recognize progress, create a feedback channel, and personally demonstrate new system usage', fr: 'Identifier des champions du changement, organiser des sessions de pratique graduelles, reconnaître les progrès, créer un canal de retour d\'information et démontrer personnellement l\'utilisation du nouveau système' }, value: 100 }, { id: 'b', text: { es: 'Dar un ultimátum al equipo para que aprenda el nuevo sistema en 2 semanas', en: 'Give the team an ultimatum to learn the new system in 2 weeks', fr: 'Donner un ultimatum à l\'équipe pour apprendre le nouveau système en 2 semaines' }, value: 0 }, { id: 'c', text: { es: 'Solicitar que mantengan el sistema anterior en paralelo indefinidamente', en: 'Request to keep the previous system running in parallel indefinitely', fr: 'Demander de maintenir l\'ancien système en parallèle indéfiniment' }, value: 0 }, { id: 'd', text: { es: 'Dejar que el equipo de tecnología se encargue de toda la capacitación', en: 'Let the technology team handle all the training', fr: 'Laisser l\'équipe technologique s\'occuper de toute la formation' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bm-rd-3', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-digital-transformation', type: 'scale', content: { es: '¿Qué tan preparado se siente para liderar la transformación de su sucursal hacia un modelo híbrido (presencial + digital)?', en: 'How prepared do you feel to lead the transformation of your branch toward a hybrid model (in-person + digital)?', fr: 'À quel point vous sentez-vous préparé pour mener la transformation de votre agence vers un modèle hybride (présentiel + numérique) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No tengo experiencia con transformación digital', en: 'I have no experience with digital transformation', fr: 'Je n\'ai aucune expérience en transformation numérique' }, max: { es: 'He liderado exitosamente transformaciones digitales en sucursales', en: 'I have successfully led digital transformations in branches', fr: 'J\'ai mené avec succès des transformations numériques en agences' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bm-rd-4', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-innovation', type: 'scale', content: { es: '¿Qué tan abierto está a incorporar nuevos productos financieros (banca digital, criptoactivos, seguros embebidos) en la oferta de su sucursal?', en: 'How open are you to incorporating new financial products (digital banking, crypto assets, embedded insurance) in your branch\'s offering?', fr: 'À quel point êtes-vous ouvert à l\'incorporation de nouveaux produits financiers (banque numérique, crypto-actifs, assurance intégrée) dans l\'offre de votre agence ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero mantener la oferta tradicional probada', en: 'I prefer to maintain the proven traditional offering', fr: 'Je préfère maintenir l\'offre traditionnelle éprouvée' }, max: { es: 'Busco activamente integrar productos innovadores que respondan a nuevas necesidades', en: 'I actively seek to integrate innovative products responding to new needs', fr: 'Je cherche activement à intégrer des produits innovants répondant aux nouveaux besoins' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bm-rd-5', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-change-management', type: 'scenario', content: { es: 'El banco decide implementar un modelo de "sucursal cashless" (sin manejo de efectivo) en su ubicación como piloto. Los clientes del área son mayormente comerciantes que dependen del depósito de efectivo diario. El sindicato se opone por posibles recortes. Usted debe ejecutar la transición en 6 meses.\n\nDescriba su plan de gestión del cambio para los tres públicos afectados: clientes, equipo de la sucursal y sindicato.', en: 'The bank decides to implement a "cashless branch" model (no cash handling) at your location as a pilot. Clients in the area are mostly merchants who depend on daily cash deposits. The union opposes it due to potential cuts. You must execute the transition in 6 months.\n\nDescribe your change management plan for the three affected audiences: clients, branch team, and union.', fr: 'La banque décide de mettre en place un modèle d\'agence sans espèces dans votre emplacement comme pilote. Les clients de la zone sont principalement des commerçants dépendant des dépôts quotidiens en espèces. Le syndicat s\'oppose en raison de possibles réductions. Vous devez exécuter la transition en 6 mois.\n\nDécrivez votre plan de gestion du changement pour les trois publics affectés.' }, rubric: { es: 'Evaluar: (1) Estrategia de comunicación diferenciada por público, (2) Soluciones alternativas para clientes dependientes de efectivo (ATMs inteligentes, depósito en comercios), (3) Plan de reconversión de roles del equipo, (4) Negociación constructiva con el sindicato, (5) Cronograma de implementación gradual, (6) Métricas de éxito y plan de contingencia.', en: 'Evaluate: (1) Differentiated communication strategy per audience, (2) Alternative solutions for cash-dependent clients (smart ATMs, merchant deposits), (3) Team role conversion plan, (4) Constructive union negotiation, (5) Gradual implementation timeline, (6) Success metrics and contingency plan.', fr: 'Évaluer : (1) Stratégie de communication différenciée, (2) Solutions alternatives pour les clients dépendants des espèces, (3) Plan de reconversion des rôles, (4) Négociation constructive avec le syndicat, (5) Chronogramme de mise en œuvre graduelle, (6) Métriques de succès et plan de contingence.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-bm-rd-6', profileId: 'bank-branch-manager', categoryId: 'bank-bm-readiness', competencyId: 'bank-bm-innovation', type: 'open-text', content: { es: '¿Cómo imagina la sucursal bancaria del futuro en 5 años y qué pasos tomaría hoy para comenzar esa transformación en su sucursal actual?', en: 'How do you envision the bank branch of the future in 5 years, and what steps would you take today to begin that transformation in your current branch?', fr: 'Comment imaginez-vous l\'agence bancaire du futur dans 5 ans, et quelles mesures prendriez-vous aujourd\'hui pour commencer cette transformation dans votre agence actuelle ?' }, rubric: { es: 'Evaluar: (1) Visión clara del modelo de sucursal futura, (2) Comprensión de tendencias tecnológicas bancarias, (3) Pasos concretos y viables desde la posición actual, (4) Consideración de clientes, equipo y tecnología, (5) Innovación en experiencia del cliente, (6) Realismo y ambición equilibrados.', en: 'Evaluate: (1) Clear vision of future branch model, (2) Understanding of banking technology trends, (3) Concrete and feasible steps from current position, (4) Consideration of clients, team, and technology, (5) Innovation in customer experience, (6) Balanced realism and ambition.', fr: 'Évaluer : (1) Vision claire du modèle d\'agence futur, (2) Compréhension des tendances technologiques bancaires, (3) Étapes concrètes et réalisables, (4) Considération des clients, de l\'équipe et de la technologie, (5) Innovation en expérience client, (6) Réalisme et ambition équilibrés.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

