// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const bankLoProfessionalQuestions: Question[] = [
  { id: 'bank-lo-prof-1', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-credit-analysis', type: 'multiple-choice', content: { es: 'Un solicitante de crédito empresarial presenta estados financieros con un ratio de endeudamiento (deuda/patrimonio) de 3.5, pero un flujo de caja operativo positivo y creciente. ¿Cuál es su evaluación inicial?', en: 'A business loan applicant presents financial statements with a debt-to-equity ratio of 3.5, but positive and growing operating cash flow. What is your initial assessment?', fr: 'Un demandeur de crédit entreprise présente des états financiers avec un ratio d\'endettement (dette/capitaux propres) de 3,5, mais un flux de trésorerie opérationnel positif et croissant. Quelle est votre évaluation initiale ?' }, options: [{ id: 'a', text: { es: 'Rechazar automáticamente por alto endeudamiento', en: 'Automatically reject due to high leverage', fr: 'Rejeter automatiquement pour endettement élevé' }, value: 0 }, { id: 'b', text: { es: 'Profundizar el análisis: evaluar la naturaleza de la deuda, el sector de la empresa, la tendencia del ratio, la calidad del flujo de caja y la capacidad de servicio de deuda antes de decidir', en: 'Deepen the analysis: evaluate the nature of the debt, the company\'s sector, the ratio trend, cash flow quality, and debt service capacity before deciding', fr: 'Approfondir l\'analyse : évaluer la nature de la dette, le secteur de l\'entreprise, la tendance du ratio, la qualité du flux de trésorerie et la capacité de service de la dette avant de décider' }, value: 100 }, { id: 'c', text: { es: 'Aprobar basándose solo en el flujo de caja positivo', en: 'Approve based solely on positive cash flow', fr: 'Approuver uniquement sur la base du flux de trésorerie positif' }, value: 25 }, { id: 'd', text: { es: 'Solicitar únicamente garantías adicionales para mitigar el riesgo', en: 'Request only additional collateral to mitigate the risk', fr: 'Demander uniquement des garanties supplémentaires pour atténuer le risque' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-lo-prof-2', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-loan-structuring', type: 'multiple-choice', content: { es: 'Una PYME solicita un crédito de USD 500,000 para expandir operaciones. El flujo de caja soporta cuotas mensuales de USD 15,000. La empresa ofrece un inmueble valorado en USD 400,000 como garantía. ¿Cómo estructura el crédito?', en: 'An SME requests a USD 500,000 loan to expand operations. Cash flow supports monthly payments of USD 15,000. The company offers a property valued at USD 400,000 as collateral. How do you structure the loan?', fr: 'Une PME demande un crédit de 500 000 USD pour étendre ses opérations. Le flux de trésorerie supporte des versements mensuels de 15 000 USD. L\'entreprise offre un bien immobilier évalué à 400 000 USD en garantie. Comment structurez-vous le crédit ?' }, options: [{ id: 'a', text: { es: 'Otorgar USD 500,000 a 36 meses con cuota fija, lo que excedería la capacidad de pago del cliente', en: 'Grant USD 500,000 over 36 months with fixed installments, which would exceed the client\'s payment capacity', fr: 'Accorder 500 000 USD sur 36 mois en versements fixes, ce qui dépasserait la capacité de paiement du client' }, value: 0 }, { id: 'b', text: { es: 'Estructurar a 48 meses con cuotas de ~USD 13,500, solicitar garantía adicional para cubrir el gap entre colateral y monto, incluir covenants financieros y un período de gracia de 3 meses para la fase de inversión', en: 'Structure over 48 months with ~USD 13,500 installments, request additional collateral to cover the gap between collateral and amount, include financial covenants, and a 3-month grace period for the investment phase', fr: 'Structurer sur 48 mois avec des versements d\'environ 13 500 USD, demander une garantie supplémentaire, inclure des covenants financiers et un différé de 3 mois pour la phase d\'investissement' }, value: 100 }, { id: 'c', text: { es: 'Reducir el monto a USD 400,000 (valor de la garantía) sin considerar la necesidad real del cliente', en: 'Reduce the amount to USD 400,000 (collateral value) without considering the client\'s actual need', fr: 'Réduire le montant à 400 000 USD (valeur de la garantie) sans considérer le besoin réel du client' }, value: 50 }, { id: 'd', text: { es: 'Rechazar porque la garantía no cubre el 100% del crédito', en: 'Reject because the collateral doesn\'t cover 100% of the loan', fr: 'Rejeter parce que la garantie ne couvre pas 100% du crédit' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-lo-prof-3', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-portfolio-mgmt', type: 'multiple-choice', content: { es: 'En su cartera de créditos, un cliente que siempre pagó puntualmente acaba de retrasarse 15 días en su cuota. Además, usted nota que su empresa ha tenido rotación de personal y un cliente importante ha dejado de comprarles. ¿Qué hace?', en: 'In your loan portfolio, a client who always paid on time has just fallen 15 days behind on their installment. Additionally, you notice their company has had staff turnover and a major customer has stopped buying from them. What do you do?', fr: 'Dans votre portefeuille de crédits, un client qui payait toujours ponctuellement vient de prendre 15 jours de retard sur son versement. De plus, vous remarquez que son entreprise a eu du turnover et qu\'un client important a cessé de leur acheter. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Esperar a los 30 días de atraso para activar el proceso de cobranza', en: 'Wait until 30 days overdue to activate the collection process', fr: 'Attendre 30 jours de retard pour activer le processus de recouvrement' }, value: 0 }, { id: 'b', text: { es: 'Contactar al cliente proactivamente para evaluar su situación actual, revisar las señales de alerta temprana, analizar si requiere una reestructuración preventiva y documentar el caso', en: 'Proactively contact the client to assess their current situation, review early warning signals, analyze if preventive restructuring is needed, and document the case', fr: 'Contacter le client proactivement pour évaluer sa situation actuelle, examiner les signaux d\'alerte précoces, analyser si une restructuration préventive est nécessaire et documenter le cas' }, value: 100 }, { id: 'c', text: { es: 'Enviar una notificación formal de cobro', en: 'Send a formal collection notice', fr: 'Envoyer une notification formelle de recouvrement' }, value: 25 }, { id: 'd', text: { es: 'Clasificar el crédito como riesgo alto y provisionar', en: 'Classify the loan as high risk and provision', fr: 'Classer le crédit comme risque élevé et provisionner' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-lo-prof-4', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-credit-analysis', type: 'scale', content: { es: '¿Qué nivel de dominio tiene en el análisis de estados financieros (balance, estado de resultados, flujo de efectivo) para la evaluación crediticia?', en: 'What level of proficiency do you have in financial statement analysis (balance sheet, income statement, cash flow) for credit evaluation?', fr: 'Quel niveau de maîtrise avez-vous dans l\'analyse des états financiers (bilan, compte de résultat, flux de trésorerie) pour l\'évaluation de crédit ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento básico de lectura de estados financieros', en: 'Basic knowledge of reading financial statements', fr: 'Connaissance de base en lecture d\'états financiers' }, max: { es: 'Dominio avanzado incluyendo análisis de tendencias, ratios y proyecciones', en: 'Advanced proficiency including trend analysis, ratios, and projections', fr: 'Maîtrise avancée incluant analyse de tendances, ratios et projections' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-lo-prof-5', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-loan-structuring', type: 'scenario', content: { es: 'Un grupo empresarial familiar solicita USD 2 millones para adquirir una empresa competidora. El grupo tiene 3 empresas operativas con ventas combinadas de USD 10 millones anuales, deuda existente de USD 3 millones y propiedades no gravadas por USD 1.5 millones. La empresa objetivo tiene ventas de USD 4 millones pero ha operado con pérdidas los últimos 2 años. El patriarca de la familia (65 años) quiere que su hijo (30 años, MBA, 3 años de experiencia) dirija la empresa adquirida.\n\nEstructure la propuesta crediticia evaluando viabilidad, riesgos y condiciones.', en: 'A family business group requests USD 2 million to acquire a competing company. The group has 3 operating companies with combined sales of USD 10 million annually, existing debt of USD 3 million, and unencumbered properties worth USD 1.5 million. The target company has USD 4 million in sales but has operated at a loss for the last 2 years. The family patriarch (65 years old) wants his son (30 years old, MBA, 3 years of experience) to run the acquired company.\n\nStructure the credit proposal evaluating viability, risks, and conditions.', fr: 'Un groupe familial d\'entreprises demande 2 millions USD pour acquérir un concurrent. Le groupe a 3 entreprises opérationnelles avec des ventes combinées de 10 millions USD, une dette existante de 3 millions USD et des propriétés non grevées de 1,5 million USD. L\'entreprise cible a des ventes de 4 millions USD mais a opéré à perte les 2 dernières années.\n\nStructurez la proposition de crédit en évaluant la viabilité, les risques et les conditions.' }, rubric: { es: 'Evaluar: (1) Análisis de la capacidad de pago consolidada del grupo, (2) Evaluación de la empresa objetivo y plan de turnaround, (3) Estructura de garantías (cruce de garantías entre empresas del grupo), (4) Riesgos de concentración y sucesión familiar, (5) Condiciones y covenants apropiados, (6) Mitigantes de riesgo (experiencia del sucesor, plan de negocios).', en: 'Evaluate: (1) Consolidated group repayment capacity analysis, (2) Target company assessment and turnaround plan, (3) Collateral structure (cross-guarantees among group companies), (4) Concentration and family succession risks, (5) Appropriate conditions and covenants, (6) Risk mitigants (successor experience, business plan).', fr: 'Évaluer : (1) Analyse de la capacité de remboursement consolidée, (2) Évaluation de l\'entreprise cible et plan de redressement, (3) Structure de garanties croisées, (4) Risques de concentration et de succession, (5) Conditions et covenants appropriés, (6) Atténuants de risque.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-lo-prof-6', profileId: 'loan-officer', categoryId: 'bank-lo-professional', competencyId: 'bank-lo-portfolio-mgmt', type: 'open-text', content: { es: 'Describa su metodología para el monitoreo y seguimiento proactivo de una cartera de créditos empresariales. ¿Qué indicadores vigila, con qué frecuencia y qué acciones preventivas toma ante señales de deterioro?', en: 'Describe your methodology for proactive monitoring and follow-up of a corporate loan portfolio. What indicators do you watch, how frequently, and what preventive actions do you take when deterioration signals appear?', fr: 'Décrivez votre méthodologie de suivi et surveillance proactive d\'un portefeuille de crédits aux entreprises. Quels indicateurs surveillez-vous, à quelle fréquence et quelles actions préventives prenez-vous face aux signaux de détérioration ?' }, rubric: { es: 'Evaluar: (1) Indicadores financieros y no financieros monitoreados, (2) Frecuencia y sistematización del seguimiento, (3) Sistema de alertas tempranas, (4) Acciones preventivas escalonadas, (5) Documentación y reporteo, (6) Coordinación con áreas de cobranza y riesgo.', en: 'Evaluate: (1) Financial and non-financial indicators monitored, (2) Frequency and systematization of follow-up, (3) Early warning system, (4) Escalated preventive actions, (5) Documentation and reporting, (6) Coordination with collections and risk areas.', fr: 'Évaluer : (1) Indicateurs financiers et non financiers surveillés, (2) Fréquence et systématisation du suivi, (3) Système d\'alertes précoces, (4) Actions préventives échelonnées, (5) Documentation et reporting, (6) Coordination avec les services de recouvrement et de risque.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (2 multiple-choice + 2 scale + 1 ranking + 1 open-text) ---
export const bankLoSoftSkillsQuestions: Question[] = [
  { id: 'bank-lo-ss-1', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-negotiation', type: 'multiple-choice', content: { es: 'Un cliente solicita un crédito hipotecario y exige una tasa del 7% cuando la política del banco establece un mínimo del 9% para su perfil de riesgo. El cliente amenaza con irse a la competencia. ¿Cómo negocia?', en: 'A client requests a mortgage and demands a 7% rate when bank policy establishes a minimum of 9% for their risk profile. The client threatens to go to a competitor. How do you negotiate?', fr: 'Un client demande un crédit hypothécaire et exige un taux de 7% alors que la politique de la banque établit un minimum de 9% pour son profil de risque. Le client menace de partir à la concurrence. Comment négociez-vous ?' }, options: [{ id: 'a', text: { es: 'Explicar transparentemente la estructura de tasa, ofrecer alternativas de valor (plazo, seguros incluidos, período de gracia, programa de fidelización) que mejoren la oferta integral sin comprometer la política de pricing', en: 'Transparently explain the rate structure, offer value alternatives (term, included insurance, grace period, loyalty program) that improve the overall offer without compromising pricing policy', fr: 'Expliquer de manière transparente la structure de taux, offrir des alternatives de valeur (durée, assurances incluses, différé, programme de fidélisation) qui améliorent l\'offre globale sans compromettre la politique de tarification' }, value: 100 }, { id: 'b', text: { es: 'Acceder a la tasa solicitada para no perder al cliente', en: 'Accept the requested rate to avoid losing the client', fr: 'Accepter le taux demandé pour ne pas perdre le client' }, value: 0 }, { id: 'c', text: { es: 'Decirle que la política es inflexible y que puede buscar en otro banco', en: 'Tell them the policy is inflexible and they can look elsewhere', fr: 'Lui dire que la politique est inflexible et qu\'il peut chercher ailleurs' }, value: 25 }, { id: 'd', text: { es: 'Escalar al gerente para que autorice una excepción', en: 'Escalate to the manager to authorize an exception', fr: 'Escalader au directeur pour qu\'il autorise une exception' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-lo-ss-2', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-ethical-judgment', type: 'multiple-choice', content: { es: 'El gerente de la sucursal le pide que apruebe un crédito para un familiar suyo que no cumple con los requisitos mínimos de scoring. Le asegura que él se hace responsable. ¿Qué hace?', en: 'The branch manager asks you to approve a loan for their relative who doesn\'t meet minimum scoring requirements. They assure you they\'ll take responsibility. What do you do?', fr: 'Le directeur d\'agence vous demande d\'approuver un crédit pour un membre de sa famille qui ne remplit pas les critères minimaux de scoring. Il vous assure qu\'il en prend la responsabilité. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Rechazar la solicitud por no cumplir los requisitos, documentar la presión recibida y reportar al área de cumplimiento si persiste la presión', en: 'Reject the application for not meeting requirements, document the pressure received, and report to the compliance area if pressure persists', fr: 'Rejeter la demande pour non-conformité aux exigences, documenter la pression reçue et signaler au service de conformité si la pression persiste' }, value: 100 }, { id: 'b', text: { es: 'Aprobar el crédito ya que el gerente asume la responsabilidad', en: 'Approve the loan since the manager takes responsibility', fr: 'Approuver le crédit puisque le directeur assume la responsabilité' }, value: 0 }, { id: 'c', text: { es: 'Buscar una forma de mejorar el scoring del solicitante para que califique', en: 'Look for a way to improve the applicant\'s scoring so they qualify', fr: 'Chercher un moyen d\'améliorer le scoring du demandeur pour qu\'il soit éligible' }, value: 0 }, { id: 'd', text: { es: 'Decirle al gerente que lo presente al comité de crédito como excepción', en: 'Tell the manager to present it to the credit committee as an exception', fr: 'Dire au directeur de le présenter au comité de crédit comme exception' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-lo-ss-3', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-negotiation', type: 'scale', content: { es: '¿Qué tan efectivo se considera negociando condiciones crediticias que equilibren las necesidades del cliente con las políticas de riesgo del banco?', en: 'How effective do you consider yourself at negotiating credit terms that balance client needs with the bank\'s risk policies?', fr: 'À quel point vous considérez-vous efficace pour négocier des conditions de crédit équilibrant les besoins du client avec les politiques de risque de la banque ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me apego estrictamente a las políticas sin negociar', en: 'I strictly follow policies without negotiating', fr: 'Je m\'en tiens strictement aux politiques sans négocier' }, max: { es: 'Logro acuerdos creativos satisfactorios para ambas partes dentro de las políticas', en: 'I achieve creative agreements satisfactory for both parties within policies', fr: 'J\'obtiens des accords créatifs satisfaisants pour les deux parties dans le cadre des politiques' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-lo-ss-4', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-analytical-comm', type: 'scale', content: { es: '¿Qué tan cómodo se siente presentando análisis crediticios ante un comité de crédito o directivos superiores?', en: 'How comfortable do you feel presenting credit analyses to a credit committee or senior executives?', fr: 'À quel point êtes-vous à l\'aise pour présenter des analyses de crédit devant un comité de crédit ou des dirigeants supérieurs ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me resulta difícil presentar análisis complejos ante comités', en: 'I find it difficult to present complex analyses to committees', fr: 'J\'ai du mal à présenter des analyses complexes devant des comités' }, max: { es: 'Presento con confianza y defiendo mis recomendaciones con datos sólidos', en: 'I present confidently and defend my recommendations with solid data', fr: 'Je présente avec confiance et défends mes recommandations avec des données solides' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-lo-ss-5', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-analytical-comm', type: 'ranking', content: { es: 'Ordene los siguientes elementos por importancia al presentar un caso crediticio complejo ante el comité de crédito:', en: 'Rank the following elements by importance when presenting a complex credit case to the credit committee:', fr: 'Classez les éléments suivants par importance lors de la présentation d\'un cas de crédit complexe au comité de crédit :' }, options: [{ id: 'a', text: { es: 'Resumen ejecutivo claro con recomendación fundamentada', en: 'Clear executive summary with substantiated recommendation', fr: 'Résumé exécutif clair avec recommandation fondée' }, value: 1 }, { id: 'b', text: { es: 'Análisis detallado de capacidad de pago y flujo de caja', en: 'Detailed analysis of repayment capacity and cash flow', fr: 'Analyse détaillée de la capacité de remboursement et du flux de trésorerie' }, value: 2 }, { id: 'c', text: { es: 'Identificación y mitigación de riesgos principales', en: 'Identification and mitigation of key risks', fr: 'Identification et atténuation des risques principaux' }, value: 3 }, { id: 'd', text: { es: 'Condiciones propuestas y estructura de garantías', en: 'Proposed conditions and collateral structure', fr: 'Conditions proposées et structure de garanties' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'bank-lo-ss-6', profileId: 'loan-officer', categoryId: 'bank-lo-soft-skills', competencyId: 'bank-lo-ethical-judgment', type: 'open-text', content: { es: 'Describa una situación en la que tuvo que tomar una decisión crediticia difícil donde existía presión para aprobar un crédito que usted consideraba riesgoso. ¿Cómo manejó la situación y cuál fue el resultado?', en: 'Describe a situation where you had to make a difficult credit decision where there was pressure to approve a loan you considered risky. How did you handle the situation and what was the outcome?', fr: 'Décrivez une situation où vous avez dû prendre une décision de crédit difficile alors qu\'il y avait une pression pour approuver un prêt que vous considériez risqué. Comment avez-vous géré la situation et quel a été le résultat ?' }, rubric: { es: 'Evaluar: (1) Claridad en la identificación del dilema ético, (2) Firmeza en los estándares de riesgo, (3) Comunicación respetuosa pero firme de la posición, (4) Uso de datos y análisis para respaldar la decisión, (5) Manejo de las relaciones interpersonales, (6) Resultado y aprendizaje.', en: 'Evaluate: (1) Clarity in identifying the ethical dilemma, (2) Firmness in risk standards, (3) Respectful but firm communication of position, (4) Use of data and analysis to support the decision, (5) Handling of interpersonal relationships, (6) Outcome and learning.', fr: 'Évaluer : (1) Clarté dans l\'identification du dilemme éthique, (2) Fermeté dans les standards de risque, (3) Communication respectueuse mais ferme, (4) Utilisation de données pour soutenir la décision, (5) Gestion des relations interpersonnelles, (6) Résultat et apprentissage.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (2 multiple-choice + 2 scale + 1 scenario + 1 open-text) ---
export const bankLoReadinessQuestions: Question[] = [
  { id: 'bank-lo-rd-1', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-digital-lending', type: 'multiple-choice', content: { es: 'El banco implementa un sistema de scoring automatizado con inteligencia artificial que aprueba o rechaza el 70% de las solicitudes sin intervención humana. Su rol cambia de analista a supervisor de excepciones. ¿Cuál es su reacción?', en: 'The bank implements an AI-powered automated scoring system that approves or rejects 70% of applications without human intervention. Your role changes from analyst to exception supervisor. What is your reaction?', fr: 'La banque met en place un système de scoring automatisé par IA qui approuve ou rejette 70% des demandes sans intervention humaine. Votre rôle passe d\'analyste à superviseur d\'exceptions. Quelle est votre réaction ?' }, options: [{ id: 'a', text: { es: 'Aprovechar la oportunidad para especializarse en los casos complejos que el sistema no puede evaluar, aprender sobre el modelo de IA para retroalimentarlo y enfocarse en análisis de mayor valor', en: 'Seize the opportunity to specialize in complex cases the system can\'t evaluate, learn about the AI model to provide feedback, and focus on higher-value analysis', fr: 'Saisir l\'opportunité de se spécialiser dans les cas complexes que le système ne peut évaluer, apprendre sur le modèle d\'IA pour le rétroalimenter et se concentrer sur des analyses à plus forte valeur' }, value: 100 }, { id: 'b', text: { es: 'Preocuparse por la obsolescencia de su puesto y buscar otro empleo', en: 'Worry about job obsolescence and look for another job', fr: 'S\'inquiéter de l\'obsolescence de son poste et chercher un autre emploi' }, value: 0 }, { id: 'c', text: { es: 'Aceptar pasivamente el nuevo rol sin adaptarse', en: 'Passively accept the new role without adapting', fr: 'Accepter passivement le nouveau rôle sans s\'adapter' }, value: 25 }, { id: 'd', text: { es: 'Cuestionar la fiabilidad del sistema e insistir en revisión humana del 100%', en: 'Question the system\'s reliability and insist on 100% human review', fr: 'Remettre en question la fiabilité du système et insister sur une révision humaine à 100%' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-lo-rd-2', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-regulatory-evolution', type: 'multiple-choice', content: { es: 'El regulador emite una nueva normativa de provisiones basada en pérdidas esperadas (NIIF 9) que cambia fundamentalmente cómo se clasifican y provisionan los créditos de su cartera. ¿Cómo se prepara?', en: 'The regulator issues new provision standards based on expected losses (IFRS 9) that fundamentally change how loans in your portfolio are classified and provisioned. How do you prepare?', fr: 'Le régulateur émet de nouvelles normes de provisions basées sur les pertes attendues (IFRS 9) qui changent fondamentalement la classification et le provisionnement des crédits de votre portefeuille. Comment vous préparez-vous ?' }, options: [{ id: 'a', text: { es: 'Inscribirse proactivamente en capacitación sobre la nueva normativa, analizar el impacto en su cartera actual, proponer ajustes a los procesos de originación y colaborar con el área de riesgos en la transición', en: 'Proactively enroll in training on the new regulation, analyze the impact on your current portfolio, propose adjustments to origination processes, and collaborate with the risk area on the transition', fr: 'S\'inscrire proactivement à une formation sur la nouvelle réglementation, analyser l\'impact sur le portefeuille actuel, proposer des ajustements aux processus d\'origination et collaborer avec le service des risques pour la transition' }, value: 100 }, { id: 'b', text: { es: 'Esperar a que el banco organice la capacitación obligatoria', en: 'Wait for the bank to organize mandatory training', fr: 'Attendre que la banque organise la formation obligatoire' }, value: 25 }, { id: 'c', text: { es: 'Dejar que el área de riesgos se encargue de los cambios', en: 'Let the risk area handle the changes', fr: 'Laisser le service des risques s\'occuper des changements' }, value: 25 }, { id: 'd', text: { es: 'Continuar con el modelo anterior hasta que sea obligatorio el cambio', en: 'Continue with the previous model until the change is mandatory', fr: 'Continuer avec le modèle précédent jusqu\'à ce que le changement soit obligatoire' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-lo-rd-3', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-digital-lending', type: 'scale', content: { es: '¿Qué tan familiarizado está con plataformas de originación digital de crédito y modelos de scoring basados en inteligencia artificial?', en: 'How familiar are you with digital credit origination platforms and AI-based scoring models?', fr: 'À quel point êtes-vous familiarisé avec les plateformes d\'origination numérique de crédit et les modèles de scoring basés sur l\'intelligence artificielle ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No he trabajado con plataformas digitales de crédito', en: 'I have not worked with digital credit platforms', fr: 'Je n\'ai pas travaillé avec des plateformes numériques de crédit' }, max: { es: 'Uso cotidianamente herramientas digitales y comprendo modelos de IA crediticia', en: 'I use digital tools daily and understand AI credit models', fr: 'J\'utilise quotidiennement des outils numériques et comprends les modèles d\'IA de crédit' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-lo-rd-4', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-alt-data', type: 'scale', content: { es: '¿Qué tan abierto está a utilizar datos alternativos (transacciones digitales, comportamiento en redes, historiales de pagos de servicios) como complemento al análisis crediticio tradicional?', en: 'How open are you to using alternative data (digital transactions, social behavior, utility payment histories) as a complement to traditional credit analysis?', fr: 'À quel point êtes-vous ouvert à l\'utilisation de données alternatives (transactions numériques, comportement en ligne, historiques de paiements de services) comme complément à l\'analyse de crédit traditionnelle ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero basarme solo en información financiera tradicional', en: 'I prefer to rely solely on traditional financial information', fr: 'Je préfère me baser uniquement sur l\'information financière traditionnelle' }, max: { es: 'Integro activamente datos alternativos para enriquecer la evaluación', en: 'I actively integrate alternative data to enrich the assessment', fr: 'J\'intègre activement des données alternatives pour enrichir l\'évaluation' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-lo-rd-5', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-alt-data', type: 'scenario', content: { es: 'El banco lanza un programa de microcréditos digitales para emprendedores sin historial crediticio formal. Se utilizará un modelo de scoring basado en datos alternativos (historial de pagos de servicios, transacciones en billeteras digitales, datos de redes sociales profesionales). A usted le asignan liderar la validación del modelo y definir las políticas de otorgamiento.\n\n¿Cómo diseñaría el marco de evaluación para estos créditos no convencionales, asegurando inclusión financiera sin comprometer la calidad de la cartera?', en: 'The bank launches a digital microcredit program for entrepreneurs without formal credit history. An alternative data-based scoring model will be used (utility payment history, digital wallet transactions, professional social media data). You are assigned to lead model validation and define granting policies.\n\nHow would you design the evaluation framework for these non-conventional loans, ensuring financial inclusion without compromising portfolio quality?', fr: 'La banque lance un programme de microcrédits numériques pour les entrepreneurs sans historique de crédit formel. Un modèle de scoring basé sur des données alternatives sera utilisé. Vous êtes chargé de diriger la validation du modèle et de définir les politiques d\'octroi.\n\nComment concevriez-vous le cadre d\'évaluation pour ces crédits non conventionnels ?' }, rubric: { es: 'Evaluar: (1) Metodología de validación del modelo alternativo, (2) Variables de datos alternativos y su poder predictivo, (3) Políticas de otorgamiento escalonadas (montos iniciales bajos con crecimiento), (4) Métricas de monitoreo y ajuste del modelo, (5) Balance entre inclusión y riesgo, (6) Cumplimiento regulatorio y protección de datos.', en: 'Evaluate: (1) Alternative model validation methodology, (2) Alternative data variables and predictive power, (3) Tiered granting policies (low initial amounts with growth), (4) Model monitoring and adjustment metrics, (5) Balance between inclusion and risk, (6) Regulatory compliance and data protection.', fr: 'Évaluer : (1) Méthodologie de validation du modèle alternatif, (2) Variables de données alternatives et pouvoir prédictif, (3) Politiques d\'octroi échelonnées, (4) Métriques de suivi et ajustement, (5) Équilibre inclusion/risque, (6) Conformité réglementaire et protection des données.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-lo-rd-6', profileId: 'loan-officer', categoryId: 'bank-lo-readiness', competencyId: 'bank-lo-regulatory-evolution', type: 'open-text', content: { es: '¿Cómo se mantiene actualizado respecto a cambios regulatorios en materia crediticia y financiera? Describa sus fuentes de información, frecuencia de actualización y cómo aplica los nuevos conocimientos a su trabajo diario.', en: 'How do you stay updated on regulatory changes in credit and financial matters? Describe your information sources, update frequency, and how you apply new knowledge to your daily work.', fr: 'Comment restez-vous à jour concernant les changements réglementaires en matière de crédit et de finances ? Décrivez vos sources d\'information, la fréquence de mise à jour et comment vous appliquez les nouvelles connaissances à votre travail quotidien.' }, rubric: { es: 'Evaluar: (1) Diversidad de fuentes (regulador, asociaciones, publicaciones especializadas), (2) Proactividad y sistematización del aprendizaje, (3) Capacidad de traducir regulaciones a procesos prácticos, (4) Compartir conocimientos con el equipo, (5) Certificaciones o educación continua, (6) Ejemplos concretos de adaptación regulatoria.', en: 'Evaluate: (1) Diversity of sources (regulator, associations, specialized publications), (2) Proactivity and learning systematization, (3) Ability to translate regulations into practical processes, (4) Knowledge sharing with team, (5) Certifications or continuing education, (6) Concrete examples of regulatory adaptation.', fr: 'Évaluer : (1) Diversité des sources, (2) Proactivité et systématisation, (3) Traduction des réglementations en processus pratiques, (4) Partage des connaissances, (5) Certifications ou formation continue, (6) Exemples concrets d\'adaptation réglementaire.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

