// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const bankIaProfessionalQuestions: Question[] = [
  { id: 'bank-ia-prof-1', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-market-knowledge', type: 'multiple-choice', content: { es: 'La Reserva Federal anuncia un aumento inesperado de 50 puntos base en la tasa de interés. Un cliente con un portafolio concentrado en bonos de largo plazo le pide consejo inmediato. ¿Qué recomienda?', en: 'The Federal Reserve announces an unexpected 50 basis point interest rate hike. A client with a portfolio concentrated in long-term bonds asks for immediate advice. What do you recommend?', fr: 'La Réserve fédérale annonce une hausse inattendue de 50 points de base du taux d\'intérêt. Un client avec un portefeuille concentré en obligations à long terme vous demande un conseil immédiat. Que recommandez-vous ?' }, options: [{ id: 'a', text: { es: 'Vender inmediatamente todos los bonos de largo plazo', en: 'Immediately sell all long-term bonds', fr: 'Vendre immédiatement toutes les obligations à long terme' }, value: 0 }, { id: 'b', text: { es: 'Evaluar el impacto en la duración del portafolio, recomendar un rebalanceo gradual hacia bonos de menor duración o tasa variable, considerar el horizonte temporal del cliente y no tomar decisiones precipitadas basadas en un solo evento', en: 'Evaluate the portfolio duration impact, recommend gradual rebalancing toward shorter-duration or floating-rate bonds, consider the client\'s time horizon, and avoid hasty decisions based on a single event', fr: 'Évaluer l\'impact sur la duration du portefeuille, recommander un rééquilibrage graduel vers des obligations de plus courte durée ou à taux variable, considérer l\'horizon temporel du client et éviter les décisions précipitées' }, value: 100 }, { id: 'c', text: { es: 'Decirle al cliente que no se preocupe, que los mercados siempre se recuperan', en: 'Tell the client not to worry, markets always recover', fr: 'Dire au client de ne pas s\'inquiéter, les marchés se remettent toujours' }, value: 25 }, { id: 'd', text: { es: 'Mover todo el portafolio a renta variable para aprovechar la oportunidad', en: 'Move the entire portfolio to equities to take advantage of the opportunity', fr: 'Déplacer tout le portefeuille vers les actions pour profiter de l\'opportunité' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-ia-prof-2', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-portfolio-advisory', type: 'multiple-choice', content: { es: 'Un matrimonio de 45 años, con ingresos estables de USD 120,000 anuales y ahorro de USD 300,000, quiere invertir para la universidad de sus hijos (en 5 años) y su jubilación (en 20 años). ¿Cómo estructura la recomendación?', en: 'A 45-year-old couple with stable income of USD 120,000/year and USD 300,000 in savings wants to invest for their children\'s college (in 5 years) and retirement (in 20 years). How do you structure the recommendation?', fr: 'Un couple de 45 ans avec un revenu stable de 120 000 USD/an et 300 000 USD d\'épargne souhaite investir pour l\'université de ses enfants (dans 5 ans) et sa retraite (dans 20 ans). Comment structurez-vous la recommandation ?' }, options: [{ id: 'a', text: { es: 'Crear dos sub-portafolios: uno conservador de corto plazo para educación (60% renta fija, 30% mixto, 10% liquidez) y otro de crecimiento para jubilación (60% renta variable diversificada, 30% renta fija, 10% alternativos), con revisión periódica', en: 'Create two sub-portfolios: a conservative short-term one for education (60% fixed income, 30% mixed, 10% cash) and a growth one for retirement (60% diversified equities, 30% fixed income, 10% alternatives), with periodic review', fr: 'Créer deux sous-portefeuilles : un conservateur à court terme pour l\'éducation (60% taux fixe, 30% mixte, 10% liquidités) et un de croissance pour la retraite (60% actions diversifiées, 30% taux fixe, 10% alternatifs), avec révision périodique' }, value: 100 }, { id: 'b', text: { es: 'Invertir todo en un fondo balanceado genérico', en: 'Invest everything in a generic balanced fund', fr: 'Tout investir dans un fonds équilibré générique' }, value: 25 }, { id: 'c', text: { es: 'Poner todo en renta variable porque el horizonte combinado es largo', en: 'Put everything in equities because the combined horizon is long', fr: 'Tout mettre en actions car l\'horizon combiné est long' }, value: 0 }, { id: 'd', text: { es: 'Recomendar depósitos a plazo fijo por su seguridad', en: 'Recommend fixed-term deposits for their safety', fr: 'Recommander des dépôts à terme fixe pour leur sécurité' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-ia-prof-3', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-suitability', type: 'multiple-choice', content: { es: 'Un cliente jubilado de 72 años con ahorros de vida de USD 200,000 le pide que invierta el 80% en criptomonedas porque "su nieto le dice que es el futuro". ¿Cómo procede?', en: 'A 72-year-old retired client with life savings of USD 200,000 asks you to invest 80% in cryptocurrencies because "their grandchild says it\'s the future." How do you proceed?', fr: 'Un client retraité de 72 ans avec des économies de toute une vie de 200 000 USD vous demande d\'investir 80% en cryptomonnaies parce que « son petit-fils dit que c\'est l\'avenir ». Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Ejecutar la orden ya que es la voluntad del cliente', en: 'Execute the order as it is the client\'s wish', fr: 'Exécuter l\'ordre car c\'est la volonté du client' }, value: 0 }, { id: 'b', text: { es: 'Realizar el perfil de riesgo formal, explicar detalladamente los riesgos de las criptomonedas vs. su perfil conservador, documentar la asesoría, y si insiste, limitar la exposición al porcentaje adecuado según su perfil con documentación de aceptación de riesgo', en: 'Conduct formal risk profiling, explain cryptocurrency risks in detail vs. their conservative profile, document the advisory, and if they insist, limit exposure to the appropriate percentage per their profile with risk acceptance documentation', fr: 'Réaliser le profilage de risque formel, expliquer en détail les risques des cryptomonnaies par rapport à leur profil conservateur, documenter le conseil, et s\'il insiste, limiter l\'exposition au pourcentage approprié avec documentation d\'acceptation des risques' }, value: 100 }, { id: 'c', text: { es: 'Negarse absolutamente a invertir en criptomonedas', en: 'Absolutely refuse to invest in cryptocurrencies', fr: 'Refuser absolument d\'investir en cryptomonnaies' }, value: 50 }, { id: 'd', text: { es: 'Invertir un porcentaje menor sin consultar al cliente', en: 'Invest a smaller percentage without consulting the client', fr: 'Investir un pourcentage moindre sans consulter le client' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-ia-prof-4', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-market-knowledge', type: 'scale', content: { es: '¿Qué nivel de conocimiento tiene sobre los distintos tipos de instrumentos de inversión (renta fija, variable, derivados, fondos, ETFs, productos estructurados)?', en: 'What level of knowledge do you have about different types of investment instruments (fixed income, equities, derivatives, funds, ETFs, structured products)?', fr: 'Quel niveau de connaissance avez-vous sur les différents types d\'instruments d\'investissement (taux fixe, actions, dérivés, fonds, ETFs, produits structurés) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco solo productos básicos (depósitos, bonos simples)', en: 'I only know basic products (deposits, simple bonds)', fr: 'Je ne connais que les produits de base (dépôts, obligations simples)' }, max: { es: 'Dominio amplio de toda la gama de instrumentos incluyendo productos estructurados y derivados', en: 'Broad command of the full range of instruments including structured products and derivatives', fr: 'Maîtrise étendue de toute la gamme d\'instruments incluant produits structurés et dérivés' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-ia-prof-5', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-portfolio-advisory', type: 'scenario', content: { es: 'Un empresario exitoso de 50 años acaba de vender su empresa por USD 5 millones. Nunca ha invertido en mercados financieros; todo su patrimonio estaba en la empresa. Tiene gastos mensuales de USD 15,000, quiere mantener su nivel de vida, dejar herencia a sus 3 hijos y "no perder el dinero". Está ansioso porque es la primera vez que tiene liquidez significativa.\n\nDiseñe una propuesta integral de inversión y asesoría patrimonial.', en: 'A successful 50-year-old entrepreneur has just sold their company for USD 5 million. They have never invested in financial markets; all their wealth was in the business. Monthly expenses are USD 15,000, they want to maintain their lifestyle, leave inheritance for their 3 children, and "not lose the money." They are anxious because it\'s their first time having significant liquidity.\n\nDesign a comprehensive investment and wealth advisory proposal.', fr: 'Un entrepreneur prospère de 50 ans vient de vendre son entreprise pour 5 millions USD. Il n\'a jamais investi sur les marchés financiers. Ses dépenses mensuelles sont de 15 000 USD, il veut maintenir son niveau de vie, laisser un héritage à ses 3 enfants et « ne pas perdre l\'argent ».\n\nConcevoir une proposition intégrale d\'investissement et de conseil patrimonial.' }, rubric: { es: 'Evaluar: (1) Proceso de perfilamiento emocional y educación financiera del cliente, (2) Asignación estratégica de activos por objetivos (liquidez, ingreso, crecimiento, herencia), (3) Diversificación adecuada y gestión del riesgo, (4) Estructura fiscal eficiente, (5) Plan de comunicación y revisión periódica, (6) Manejo de la ansiedad y expectativas del cliente.', en: 'Evaluate: (1) Client emotional profiling and financial education process, (2) Strategic asset allocation by objectives (liquidity, income, growth, inheritance), (3) Adequate diversification and risk management, (4) Tax-efficient structure, (5) Communication and periodic review plan, (6) Handling of client anxiety and expectations.', fr: 'Évaluer : (1) Profilage émotionnel et éducation financière du client, (2) Allocation stratégique par objectifs, (3) Diversification et gestion du risque, (4) Structure fiscalement efficiente, (5) Plan de communication et révision périodique, (6) Gestion de l\'anxiété et des attentes du client.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-ia-prof-6', profileId: 'investment-advisor', categoryId: 'bank-ia-professional', competencyId: 'bank-ia-suitability', type: 'open-text', content: { es: 'Explique cómo realiza el proceso de perfilamiento de riesgo de un nuevo cliente inversionista y cómo asegura que las recomendaciones de inversión sean idóneas (suitability) durante toda la relación.', en: 'Explain how you conduct the risk profiling process for a new investor client and how you ensure investment recommendations remain suitable throughout the relationship.', fr: 'Expliquez comment vous réalisez le processus de profilage de risque d\'un nouveau client investisseur et comment vous vous assurez que les recommandations d\'investissement restent adéquates tout au long de la relation.' }, rubric: { es: 'Evaluar: (1) Metodología de perfilamiento (cuestionario, entrevista, análisis de necesidades), (2) Documentación y formalización del perfil, (3) Alineación producto-perfil, (4) Revisión periódica del perfil ante cambios de vida, (5) Registro de asesoría y consentimiento informado, (6) Cumplimiento regulatorio de suitability.', en: 'Evaluate: (1) Profiling methodology (questionnaire, interview, needs analysis), (2) Profile documentation and formalization, (3) Product-profile alignment, (4) Periodic profile review with life changes, (5) Advisory records and informed consent, (6) Suitability regulatory compliance.', fr: 'Évaluer : (1) Méthodologie de profilage, (2) Documentation et formalisation du profil, (3) Alignement produit-profil, (4) Révision périodique du profil, (5) Registre de conseil et consentement éclairé, (6) Conformité réglementaire d\'adéquation.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (2 multiple-choice + 2 scale + 1 ranking + 1 open-text) ---
export const bankIaSoftSkillsQuestions: Question[] = [
  { id: 'bank-ia-ss-1', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-trust-building', type: 'multiple-choice', content: { es: 'Un cliente de alto patrimonio se queja porque su portafolio perdió 8% en el último trimestre (aunque el mercado cayó 15%). Está considerando retirar todo y ponerlo en depósitos bancarios. ¿Cómo responde?', en: 'A high-net-worth client complains because their portfolio lost 8% in the last quarter (although the market fell 15%). They\'re considering withdrawing everything and putting it in bank deposits. How do you respond?', fr: 'Un client à forte valeur patrimoniale se plaint car son portefeuille a perdu 8% au dernier trimestre (bien que le marché ait chuté de 15%). Il envisage de tout retirer et de le mettre en dépôts bancaires. Comment répondez-vous ?' }, options: [{ id: 'a', text: { es: 'Contextualizar el rendimiento vs. el mercado, revisar juntos la estrategia de largo plazo, mostrar el impacto que tendría salir ahora vs. mantenerse, y ajustar la asignación si su tolerancia al riesgo ha cambiado genuinamente', en: 'Contextualize performance vs. the market, review the long-term strategy together, show the impact of exiting now vs. staying, and adjust allocation if their risk tolerance has genuinely changed', fr: 'Contextualiser la performance par rapport au marché, revoir ensemble la stratégie à long terme, montrer l\'impact de sortir maintenant vs. rester, et ajuster l\'allocation si leur tolérance au risque a véritablement changé' }, value: 100 }, { id: 'b', text: { es: 'Mover todo a depósitos como el cliente pide para no perderlo', en: 'Move everything to deposits as the client requests to avoid losing them', fr: 'Tout déplacer en dépôts comme le client le demande pour ne pas le perdre' }, value: 0 }, { id: 'c', text: { es: 'Minimizar las pérdidas diciendo que "son solo pérdidas en papel"', en: 'Minimize the losses saying "they\'re only paper losses"', fr: 'Minimiser les pertes en disant que « ce ne sont que des pertes sur papier »' }, value: 25 }, { id: 'd', text: { es: 'Recomendar duplicar la inversión para promediar a la baja', en: 'Recommend doubling the investment to average down', fr: 'Recommander de doubler l\'investissement pour moyenner à la baisse' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-ia-ss-2', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-financial-comm', type: 'multiple-choice', content: { es: 'Un cliente le pregunta: "¿Qué es un ETF y por qué debería tener uno en mi portafolio en vez de fondos mutuos tradicionales?" ¿Cómo lo explica?', en: 'A client asks you: "What is an ETF and why should I have one in my portfolio instead of traditional mutual funds?" How do you explain it?', fr: 'Un client vous demande : « Qu\'est-ce qu\'un ETF et pourquoi devrais-je en avoir dans mon portefeuille au lieu de fonds communs traditionnels ? » Comment l\'expliquez-vous ?' }, options: [{ id: 'a', text: { es: 'Usar una analogía cotidiana ("es como comprar una canasta de frutas variadas en vez de frutas individuales"), explicar ventajas (costos bajos, diversificación, liquidez) y desventajas vs. fondos activos, y relacionarlo con su situación específica', en: 'Use an everyday analogy ("it\'s like buying a basket of assorted fruits instead of individual fruits"), explain advantages (low costs, diversification, liquidity) and disadvantages vs. active funds, and relate it to their specific situation', fr: 'Utiliser une analogie quotidienne, expliquer les avantages (coûts bas, diversification, liquidité) et inconvénients par rapport aux fonds actifs, et le relier à leur situation spécifique' }, value: 100 }, { id: 'b', text: { es: 'Explicar con terminología técnica detallada los mecanismos de creación/redención del ETF', en: 'Explain with detailed technical terminology the ETF creation/redemption mechanisms', fr: 'Expliquer avec une terminologie technique détaillée les mécanismes de création/rachat des ETF' }, value: 25 }, { id: 'c', text: { es: 'Decirle que los ETFs son mejores y punto, sin dar explicación detallada', en: 'Tell them ETFs are better, period, without detailed explanation', fr: 'Lui dire que les ETF sont meilleurs, point, sans explication détaillée' }, value: 0 }, { id: 'd', text: { es: 'Enviarle un artículo de internet sobre ETFs para que lo lea por su cuenta', en: 'Send them an internet article about ETFs to read on their own', fr: 'Lui envoyer un article internet sur les ETF pour qu\'il le lise par lui-même' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-ia-ss-3', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-trust-building', type: 'scale', content: { es: '¿Qué tan efectivo se considera generando relaciones de largo plazo con clientes de alto patrimonio?', en: 'How effective do you consider yourself at generating long-term relationships with high-net-worth clients?', fr: 'À quel point vous considérez-vous efficace pour générer des relations à long terme avec des clients à forte valeur patrimoniale ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me enfoco más en la transacción que en la relación', en: 'I focus more on the transaction than the relationship', fr: 'Je me concentre davantage sur la transaction que sur la relation' }, max: { es: 'Mantengo relaciones sólidas y de confianza que generan referidos naturales', en: 'I maintain solid trust relationships that generate natural referrals', fr: 'Je maintiens des relations solides de confiance qui génèrent des recommandations naturelles' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-ia-ss-4', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-needs-discovery', type: 'scale', content: { es: '¿Qué tan hábil se considera para descubrir las verdaderas necesidades financieras y metas de vida de un cliente más allá de lo que expresan inicialmente?', en: 'How skilled do you consider yourself at discovering a client\'s true financial needs and life goals beyond what they initially express?', fr: 'À quel point vous considérez-vous habile pour découvrir les véritables besoins financiers et objectifs de vie d\'un client au-delà de ce qu\'il exprime initialement ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me baso en lo que el cliente dice explícitamente', en: 'I rely on what the client explicitly states', fr: 'Je me base sur ce que le client dit explicitement' }, max: { es: 'Descubro necesidades profundas mediante escucha activa y preguntas estratégicas', en: 'I discover deep needs through active listening and strategic questioning', fr: 'Je découvre des besoins profonds grâce à l\'écoute active et au questionnement stratégique' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-ia-ss-5', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-needs-discovery', type: 'ranking', content: { es: 'Ordene las siguientes preguntas por importancia al realizar la primera reunión con un nuevo cliente patrimonial:', en: 'Rank the following questions by importance when conducting the first meeting with a new wealth client:', fr: 'Classez les questions suivantes par importance lors de la première réunion avec un nouveau client patrimonial :' }, options: [{ id: 'a', text: { es: '¿Cuáles son sus metas financieras a corto, mediano y largo plazo?', en: 'What are your short, medium, and long-term financial goals?', fr: 'Quels sont vos objectifs financiers à court, moyen et long terme ?' }, value: 1 }, { id: 'b', text: { es: '¿Cuál es su situación patrimonial actual completa (activos, pasivos, ingresos, gastos)?', en: 'What is your complete current financial situation (assets, liabilities, income, expenses)?', fr: 'Quelle est votre situation patrimoniale actuelle complète (actifs, passifs, revenus, dépenses) ?' }, value: 2 }, { id: 'c', text: { es: '¿Qué experiencia tiene invirtiendo y cómo se siente ante la volatilidad?', en: 'What investment experience do you have and how do you feel about volatility?', fr: 'Quelle expérience avez-vous en investissement et comment vous sentez-vous face à la volatilité ?' }, value: 3 }, { id: 'd', text: { es: '¿Qué le quita el sueño respecto a su dinero y su futuro financiero?', en: 'What keeps you up at night regarding your money and financial future?', fr: 'Qu\'est-ce qui vous empêche de dormir concernant votre argent et votre avenir financier ?' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'bank-ia-ss-6', profileId: 'investment-advisor', categoryId: 'bank-ia-soft-skills', competencyId: 'bank-ia-financial-comm', type: 'open-text', content: { es: 'Explique cómo adaptaría su estilo de comunicación financiera al asesorar a tres perfiles distintos: (1) un empresario agresivo que quiere altos rendimientos, (2) una viuda conservadora que necesita preservar capital, (3) un joven profesional que empieza a invertir.', en: 'Explain how you would adapt your financial communication style when advising three different profiles: (1) an aggressive entrepreneur seeking high returns, (2) a conservative widow needing to preserve capital, (3) a young professional starting to invest.', fr: 'Expliquez comment vous adapteriez votre style de communication financière en conseillant trois profils différents : (1) un entrepreneur agressif cherchant de hauts rendements, (2) une veuve conservatrice devant préserver le capital, (3) un jeune professionnel commençant à investir.' }, rubric: { es: 'Evaluar: (1) Adaptación del lenguaje y nivel técnico por perfil, (2) Empatía y comprensión de la situación emocional de cada uno, (3) Enfoque en los objetivos específicos de cada perfil, (4) Manejo de expectativas realistas, (5) Educación financiera adaptada, (6) Consistencia en el rigor técnico independientemente del perfil.', en: 'Evaluate: (1) Language and technical level adaptation per profile, (2) Empathy and understanding of each one\'s emotional situation, (3) Focus on each profile\'s specific objectives, (4) Realistic expectations management, (5) Adapted financial education, (6) Consistency in technical rigor regardless of profile.', fr: 'Évaluer : (1) Adaptation du langage et du niveau technique par profil, (2) Empathie et compréhension de la situation émotionnelle, (3) Focus sur les objectifs spécifiques, (4) Gestion des attentes réalistes, (5) Éducation financière adaptée, (6) Cohérence dans la rigueur technique.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (2 multiple-choice + 2 scale + 1 scenario + 1 open-text) ---
