// --- Professional (3 multiple-choice + 1 scale + 1 scenario + 1 open-text) ---
export const bankBtProfessionalQuestions: Question[] = [
  { id: 'bank-bt-prof-1', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-transactions', type: 'multiple-choice', content: { es: 'Un cliente solicita una transferencia internacional de USD 8,000 a una cuenta en otro país. ¿Cuáles son los pasos correctos a seguir?', en: 'A client requests an international wire transfer of USD 8,000 to an account in another country. What are the correct steps to follow?', fr: 'Un client demande un virement international de 8 000 USD vers un compte dans un autre pays. Quelles sont les étapes correctes à suivre ?' }, options: [{ id: 'a', text: { es: 'Procesar la transferencia inmediatamente para dar buen servicio', en: 'Process the transfer immediately to provide good service', fr: 'Traiter le virement immédiatement pour offrir un bon service' }, value: 0 }, { id: 'b', text: { es: 'Verificar la identidad del cliente, confirmar los datos del beneficiario (nombre, banco, SWIFT/BIC, cuenta), aplicar los controles de PLD/KYC, informar las comisiones y tipo de cambio, obtener la firma en el formulario y procesar con doble verificación', en: 'Verify client identity, confirm beneficiary details (name, bank, SWIFT/BIC, account), apply AML/KYC controls, inform about fees and exchange rate, obtain signature on the form, and process with double verification', fr: 'Vérifier l\'identité du client, confirmer les coordonnées du bénéficiaire (nom, banque, SWIFT/BIC, compte), appliquer les contrôles LCB/KYC, informer des frais et du taux de change, obtenir la signature sur le formulaire et traiter avec double vérification' }, value: 100 }, { id: 'c', text: { es: 'Derivar al cliente con un supervisor porque las transferencias internacionales no son responsabilidad del cajero', en: 'Refer the client to a supervisor because international transfers are not the teller\'s responsibility', fr: 'Diriger le client vers un superviseur car les virements internationaux ne sont pas de la responsabilité du caissier' }, value: 25 }, { id: 'd', text: { es: 'Solicitar solo la identificación y procesar la transferencia', en: 'Request only identification and process the transfer', fr: 'Demander uniquement l\'identification et traiter le virement' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bt-prof-2', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-cash-handling', type: 'multiple-choice', content: { es: 'Al contar un depósito en efectivo de USD 5,000, usted detecta que dos billetes de USD 100 presentan características sospechosas (la textura del papel es diferente y la marca de agua es borrosa). ¿Qué hace?', en: 'While counting a USD 5,000 cash deposit, you detect that two USD 100 bills have suspicious characteristics (the paper texture is different and the watermark is blurry). What do you do?', fr: 'En comptant un dépôt en espèces de 5 000 USD, vous détectez que deux billets de 100 USD présentent des caractéristiques suspectes (la texture du papier est différente et le filigrane est flou). Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Devolver los billetes al cliente y pedirle que los cambie', en: 'Return the bills to the client and ask them to exchange them', fr: 'Rendre les billets au client et lui demander de les échanger' }, value: 0 }, { id: 'b', text: { es: 'Retener los billetes sospechosos según el protocolo, verificar con el detector de falsificaciones, informar al cliente sobre la retención, llenar el formulario de incautación y notificar al supervisor para el reporte a las autoridades', en: 'Retain the suspicious bills per protocol, verify with the counterfeit detector, inform the client about the retention, fill out the seizure form, and notify the supervisor for reporting to authorities', fr: 'Retenir les billets suspects selon le protocole, vérifier avec le détecteur de contrefaçon, informer le client de la rétention, remplir le formulaire de saisie et notifier le superviseur pour le signalement aux autorités' }, value: 100 }, { id: 'c', text: { es: 'Aceptar el depósito completo para no incomodar al cliente', en: 'Accept the full deposit to avoid inconveniencing the client', fr: 'Accepter le dépôt complet pour ne pas incommoder le client' }, value: 0 }, { id: 'd', text: { es: 'Rechazar todo el depósito por los billetes sospechosos', en: 'Reject the entire deposit because of the suspicious bills', fr: 'Rejeter tout le dépôt à cause des billets suspects' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bt-prof-3', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-fraud-prevention', type: 'multiple-choice', content: { es: 'Una persona de la tercera edad se presenta a retirar USD 15,000 de su cuenta de ahorros. Se ve nerviosa, mira constantemente su teléfono y dice que necesita el dinero para "pagar una multa del gobierno". ¿Qué alerta debería activarse y cómo actúa?', en: 'An elderly person comes to withdraw USD 15,000 from their savings account. They appear nervous, constantly check their phone, and say they need the money to "pay a government fine." What alert should be triggered and how do you act?', fr: 'Une personne âgée se présente pour retirer 15 000 USD de son compte d\'épargne. Elle semble nerveuse, regarde constamment son téléphone et dit qu\'elle a besoin de l\'argent pour « payer une amende gouvernementale ». Quelle alerte devrait se déclencher et comment agissez-vous ?' }, options: [{ id: 'a', text: { es: 'Procesar el retiro ya que el cliente tiene fondos suficientes', en: 'Process the withdrawal since the client has sufficient funds', fr: 'Traiter le retrait car le client a des fonds suffisants' }, value: 0 }, { id: 'b', text: { es: 'Reconocer los indicadores de posible estafa a adulto mayor, alertar discretamente al supervisor, intentar conversar con el cliente en privado sobre las señales de fraude, y si se confirma la sospecha, reportar e intentar proteger al cliente', en: 'Recognize indicators of possible elder fraud, discreetly alert the supervisor, try to privately talk with the client about fraud indicators, and if suspicion is confirmed, report and try to protect the client', fr: 'Reconnaître les indicateurs de possible arnaque aux personnes âgées, alerter discrètement le superviseur, essayer de parler en privé avec le client des indicateurs de fraude, et si le soupçon est confirmé, signaler et protéger le client' }, value: 100 }, { id: 'c', text: { es: 'Decirle al cliente que parece una estafa y negarse a procesar', en: 'Tell the client it seems like a scam and refuse to process', fr: 'Dire au client que cela semble être une arnaque et refuser de traiter' }, value: 50 }, { id: 'd', text: { es: 'Pedir más documentación sobre la supuesta multa', en: 'Ask for more documentation about the alleged fine', fr: 'Demander plus de documentation sur l\'amende présumée' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bt-prof-4', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-transactions', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene procesando transacciones bancarias en sistemas core (depósitos, retiros, transferencias, pagos de servicios, cambio de divisas)?', en: 'What level of experience do you have processing banking transactions in core systems (deposits, withdrawals, transfers, bill payments, foreign exchange)?', fr: 'Quel niveau d\'expérience avez-vous dans le traitement des transactions bancaires dans les systèmes centraux (dépôts, retraits, transferts, paiements de services, change de devises) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Sin experiencia en sistemas bancarios', en: 'No experience in banking systems', fr: 'Aucune expérience avec les systèmes bancaires' }, max: { es: 'Dominio completo de múltiples tipos de transacciones y sistemas', en: 'Complete mastery of multiple transaction types and systems', fr: 'Maîtrise complète de multiples types de transactions et systèmes' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bt-prof-5', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-fraud-prevention', type: 'scenario', content: { es: 'Durante una mañana concurrida, un hombre bien vestido presenta un cheque de gerencia por USD 25,000 de otro banco local y pide que lo deposite y le autoricen un retiro parcial de USD 10,000 de inmediato. El cheque parece auténtico pero usted no puede verificar su autenticidad instantáneamente. El cliente dice que tiene una emergencia y presiona por la rapidez.\n\nDescriba paso a paso cómo manejaría esta situación, considerando los riesgos y los protocolos de seguridad.', en: 'During a busy morning, a well-dressed man presents a cashier\'s check for USD 25,000 from another local bank and asks to deposit it and authorize a partial withdrawal of USD 10,000 immediately. The check appears authentic but you cannot instantly verify its authenticity. The client claims an emergency and pushes for speed.\n\nDescribe step by step how you would handle this situation, considering risks and security protocols.', fr: 'Pendant une matinée chargée, un homme bien habillé présente un chèque de banque de 25 000 USD d\'une autre banque locale et demande de le déposer et d\'autoriser un retrait partiel de 10 000 USD immédiatement. Le chèque semble authentique mais vous ne pouvez pas vérifier son authenticité instantanément.\n\nDécrivez étape par étape comment vous géreriez cette situation.' }, rubric: { es: 'Evaluar: (1) No ceder a la presión del tiempo, (2) Verificar identidad y antigüedad de cuenta del depositante, (3) Aplicar política de retención de fondos hasta verificación del cheque, (4) Contactar al banco emisor para verificación, (5) Explicar al cliente los procedimientos de protección, (6) Involucrar al supervisor en caso de insistencia.', en: 'Evaluate: (1) Not yielding to time pressure, (2) Verifying depositor identity and account standing, (3) Applying funds hold policy until check verification, (4) Contacting issuing bank for verification, (5) Explaining protection procedures to client, (6) Involving supervisor if client insists.', fr: 'Évaluer : (1) Ne pas céder à la pression du temps, (2) Vérifier l\'identité et l\'ancienneté du compte, (3) Appliquer la politique de rétention des fonds, (4) Contacter la banque émettrice, (5) Expliquer les procédures de protection, (6) Impliquer le superviseur en cas d\'insistance.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-bt-prof-6', profileId: 'bank-teller', categoryId: 'bank-bt-professional', competencyId: 'bank-bt-cash-handling', type: 'open-text', content: { es: 'Describa su rutina completa de manejo de efectivo durante un día típico: desde la apertura de caja hasta el cierre y cuadre. ¿Qué controles aplica para evitar diferencias y cómo maneja los picos de demanda?', en: 'Describe your complete cash handling routine during a typical day: from opening your drawer to closing and balancing. What controls do you apply to avoid differences and how do you handle demand peaks?', fr: 'Décrivez votre routine complète de gestion des espèces pendant une journée typique : de l\'ouverture de la caisse à la fermeture et l\'équilibrage. Quels contrôles appliquez-vous pour éviter les différences et comment gérez-vous les pics de demande ?' }, rubric: { es: 'Evaluar: (1) Procedimiento de apertura y verificación inicial, (2) Conteo y verificación durante transacciones, (3) Manejo de bóveda y solicitudes de efectivo, (4) Cuadres parciales durante el día, (5) Procedimiento de cierre y cuadre final, (6) Gestión de diferencias y picos de demanda.', en: 'Evaluate: (1) Opening procedure and initial verification, (2) Counting and verification during transactions, (3) Vault management and cash requests, (4) Partial balancing during the day, (5) Closing and final balancing procedure, (6) Managing differences and demand peaks.', fr: 'Évaluer : (1) Procédure d\'ouverture et vérification initiale, (2) Comptage et vérification pendant les transactions, (3) Gestion du coffre et demandes d\'espèces, (4) Équilibrages partiels, (5) Procédure de fermeture et équilibrage final, (6) Gestion des différences et pics de demande.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Soft Skills (2 multiple-choice + 2 scale + 1 ranking + 1 open-text) ---
export const bankBtSoftSkillsQuestions: Question[] = [
  { id: 'bank-bt-ss-1', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-customer-service', type: 'multiple-choice', content: { es: 'Un cliente llega visiblemente molesto porque lleva 20 minutos esperando en fila. Cuando llega a su ventanilla, le dice con tono agresivo: "Este banco tiene el peor servicio del mundo." ¿Cómo responde?', en: 'A client arrives visibly upset because they have been waiting in line for 20 minutes. When they reach your counter, they say aggressively: "This bank has the worst service in the world." How do you respond?', fr: 'Un client arrive visiblement contrarié car il attend depuis 20 minutes dans la file. Quand il arrive à votre guichet, il dit d\'un ton agressif : « Cette banque a le pire service au monde. » Comment répondez-vous ?' }, options: [{ id: 'a', text: { es: 'Disculparse sinceramente por la espera, mostrar empatía, atenderlo de manera eficiente y amable, y al finalizar confirmar si necesita algo más para asegurar su satisfacción', en: 'Sincerely apologize for the wait, show empathy, serve them efficiently and kindly, and upon finishing confirm if they need anything else to ensure satisfaction', fr: 'S\'excuser sincèrement pour l\'attente, montrer de l\'empathie, le servir de manière efficace et aimable, et à la fin confirmer s\'il a besoin de quelque chose d\'autre' }, value: 100 }, { id: 'b', text: { es: 'Decirle que la fila es larga porque tienen poco personal', en: 'Tell them the line is long because they\'re short-staffed', fr: 'Lui dire que la file est longue parce qu\'ils manquent de personnel' }, value: 0 }, { id: 'c', text: { es: 'Ignorar el comentario y procesar su transacción en silencio', en: 'Ignore the comment and process their transaction in silence', fr: 'Ignorer le commentaire et traiter sa transaction en silence' }, value: 25 }, { id: 'd', text: { es: 'Llamar al supervisor para que maneje al cliente difícil', en: 'Call the supervisor to handle the difficult client', fr: 'Appeler le superviseur pour gérer le client difficile' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bt-ss-2', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-accuracy', type: 'multiple-choice', content: { es: 'Son las 2:00 PM, hay 15 personas esperando y su supervisor le pide que agilice las transacciones. Un cliente le entrega un formulario de depósito con el número de cuenta parcialmente ilegible. ¿Qué hace?', en: 'It\'s 2:00 PM, there are 15 people waiting, and your supervisor asks you to speed up transactions. A client hands you a deposit form with a partially illegible account number. What do you do?', fr: 'Il est 14h00, 15 personnes attendent et votre superviseur vous demande d\'accélérer les transactions. Un client vous remet un formulaire de dépôt avec un numéro de compte partiellement illisible. Que faites-vous ?' }, options: [{ id: 'a', text: { es: 'Intentar adivinar los números faltantes basándose en el contexto', en: 'Try to guess the missing numbers based on context', fr: 'Essayer de deviner les chiffres manquants en se basant sur le contexte' }, value: 0 }, { id: 'b', text: { es: 'Pedir amablemente al cliente que confirme o reescriba el número de cuenta completo, verificar contra el sistema, y procesar solo cuando tenga certeza', en: 'Kindly ask the client to confirm or rewrite the complete account number, verify against the system, and process only when certain', fr: 'Demander aimablement au client de confirmer ou réécrire le numéro de compte complet, vérifier dans le système et traiter uniquement quand on est certain' }, value: 100 }, { id: 'c', text: { es: 'Procesar rápidamente con los números que se ven para no atrasar la fila', en: 'Process quickly with the visible numbers to avoid delaying the line', fr: 'Traiter rapidement avec les chiffres visibles pour ne pas retarder la file' }, value: 0 }, { id: 'd', text: { es: 'Pedir al cliente que llene un nuevo formulario y se forme nuevamente', en: 'Ask the client to fill out a new form and get back in line', fr: 'Demander au client de remplir un nouveau formulaire et de refaire la file' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bt-ss-3', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-customer-service', type: 'scale', content: { es: '¿Cómo califica su capacidad para mantener la amabilidad y profesionalismo durante todo un día de atención en ventanilla, incluso con clientes difíciles?', en: 'How do you rate your ability to maintain friendliness and professionalism throughout a full day of counter service, even with difficult clients?', fr: 'Comment évaluez-vous votre capacité à maintenir l\'amabilité et le professionnalisme tout au long d\'une journée de service au guichet, même avec des clients difficiles ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me cuesta mantener la compostura en días difíciles', en: 'I struggle to maintain composure on difficult days', fr: 'J\'ai du mal à garder mon calme les jours difficiles' }, max: { es: 'Mantengo siempre un trato excelente independientemente de las circunstancias', en: 'I always maintain excellent treatment regardless of circumstances', fr: 'Je maintiens toujours un traitement excellent indépendamment des circonstances' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bt-ss-4', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-teamwork', type: 'scale', content: { es: '¿Qué tan bien colabora con sus compañeros de ventanilla y otras áreas de la sucursal para mantener la fluidez operativa?', en: 'How well do you collaborate with fellow tellers and other branch areas to maintain operational flow?', fr: 'Dans quelle mesure collaborez-vous avec vos collègues guichetiers et les autres services de l\'agence pour maintenir la fluidité opérationnelle ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero trabajar de forma independiente', en: 'I prefer to work independently', fr: 'Je préfère travailler de manière indépendante' }, max: { es: 'Colaboro activamente y apoyo a compañeros cuando necesitan ayuda', en: 'I actively collaborate and support colleagues when they need help', fr: 'Je collabore activement et soutiens les collègues quand ils ont besoin d\'aide' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bt-ss-5', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-accuracy', type: 'ranking', content: { es: 'Ordene las siguientes prácticas por importancia para mantener la precisión en las transacciones de ventanilla:', en: 'Rank the following practices by importance for maintaining accuracy in counter transactions:', fr: 'Classez les pratiques suivantes par importance pour maintenir la précision dans les transactions au guichet :' }, options: [{ id: 'a', text: { es: 'Contar el efectivo dos veces antes de entregarlo', en: 'Count cash twice before handing it over', fr: 'Compter les espèces deux fois avant de les remettre' }, value: 1 }, { id: 'b', text: { es: 'Verificar el número de cuenta y monto antes de confirmar cada transacción', en: 'Verify the account number and amount before confirming each transaction', fr: 'Vérifier le numéro de compte et le montant avant de confirmer chaque transaction' }, value: 2 }, { id: 'c', text: { es: 'Realizar cuadres parciales durante los momentos de menor actividad', en: 'Perform partial balancing during slower periods', fr: 'Effectuer des équilibrages partiels pendant les moments de moindre activité' }, value: 3 }, { id: 'd', text: { es: 'Mantener el área de trabajo organizada y libre de distracciones', en: 'Keep the work area organized and free of distractions', fr: 'Maintenir l\'espace de travail organisé et libre de distractions' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'bank-bt-ss-6', profileId: 'bank-teller', categoryId: 'bank-bt-soft-skills', competencyId: 'bank-bt-customer-service', type: 'open-text', content: { es: 'Describa la mejor experiencia de servicio al cliente que usted ha brindado en una ventanilla bancaria o puesto de atención similar. ¿Qué hizo que fuera especial y qué aprendió de esa experiencia?', en: 'Describe the best customer service experience you have provided at a bank counter or similar service position. What made it special and what did you learn from that experience?', fr: 'Décrivez la meilleure expérience de service client que vous avez offerte à un guichet bancaire ou poste de service similaire. Qu\'est-ce qui l\'a rendue spéciale et qu\'avez-vous appris de cette expérience ?' }, rubric: { es: 'Evaluar: (1) Situación específica y contexto, (2) Acciones concretas que tomó, (3) Empatía y personalización del servicio, (4) Resultado y satisfacción del cliente, (5) Aprendizaje y aplicación futura, (6) Orientación genuina al servicio.', en: 'Evaluate: (1) Specific situation and context, (2) Concrete actions taken, (3) Empathy and service personalization, (4) Result and client satisfaction, (5) Learning and future application, (6) Genuine service orientation.', fr: 'Évaluer : (1) Situation spécifique et contexte, (2) Actions concrètes prises, (3) Empathie et personnalisation du service, (4) Résultat et satisfaction du client, (5) Apprentissage et application future, (6) Orientation sincère vers le service.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// --- Readiness (2 multiple-choice + 2 scale + 1 scenario + 1 open-text) ---
export const bankBtReadinessQuestions: Question[] = [
  { id: 'bank-bt-rd-1', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-automation', type: 'multiple-choice', content: { es: 'El banco instala ATMs inteligentes que permiten depósitos de efectivo y cheques, pagos de servicios y cambio de divisas — transacciones que antes solo se hacían en ventanilla. ¿Cuál es su actitud?', en: 'The bank installs smart ATMs that allow cash and check deposits, bill payments, and foreign exchange — transactions previously only done at the counter. What is your attitude?', fr: 'La banque installe des DAB intelligents permettant dépôts d\'espèces et de chèques, paiements de services et change de devises — des transactions qui se faisaient uniquement au guichet. Quelle est votre attitude ?' }, options: [{ id: 'a', text: { es: 'Aprender a usar y promover los ATMs, ayudar a los clientes a familiarizarse con la tecnología, y aprovechar el tiempo liberado para desarrollar habilidades de asesoría comercial', en: 'Learn to use and promote the ATMs, help clients become familiar with the technology, and use the freed-up time to develop commercial advisory skills', fr: 'Apprendre à utiliser et promouvoir les DAB, aider les clients à se familiariser avec la technologie et utiliser le temps libéré pour développer des compétences de conseil commercial' }, value: 100 }, { id: 'b', text: { es: 'Preocuparse porque esto significa menos trabajo y posibles despidos', en: 'Worry because this means less work and possible layoffs', fr: 'S\'inquiéter car cela signifie moins de travail et de possibles licenciements' }, value: 0 }, { id: 'c', text: { es: 'Esperar a que le capaciten formalmente antes de usar los ATMs', en: 'Wait to be formally trained before using the ATMs', fr: 'Attendre d\'être formellement formé avant d\'utiliser les DAB' }, value: 25 }, { id: 'd', text: { es: 'Seguir atendiendo las transacciones en ventanilla como siempre', en: 'Continue handling transactions at the counter as always', fr: 'Continuer à traiter les transactions au guichet comme toujours' }, value: 0 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'bank-bt-rd-2', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-role-evolution', type: 'multiple-choice', content: { es: 'Su supervisor le propone participar en un programa de capacitación para evolucionar de cajero a "asesor universal" que además de transacciones, pueda ofrecer información básica sobre productos (cuentas, tarjetas, préstamos). ¿Cómo reacciona?', en: 'Your supervisor proposes you participate in a training program to evolve from teller to "universal advisor" who, besides transactions, can provide basic information about products (accounts, cards, loans). How do you react?', fr: 'Votre superviseur vous propose de participer à un programme de formation pour évoluer de caissier à « conseiller universel » qui, en plus des transactions, peut fournir des informations de base sur les produits (comptes, cartes, prêts). Comment réagissez-vous ?' }, options: [{ id: 'a', text: { es: 'Aceptar con entusiasmo, estudiar los productos proactivamente y ver esto como una oportunidad de crecimiento profesional', en: 'Accept enthusiastically, proactively study the products, and see this as a professional growth opportunity', fr: 'Accepter avec enthousiasme, étudier les produits de manière proactive et voir cela comme une opportunité de croissance professionnelle' }, value: 100 }, { id: 'b', text: { es: 'Aceptar pero con reservas, sintiéndose más cómodo solo con las transacciones', en: 'Accept but with reservations, feeling more comfortable with just transactions', fr: 'Accepter mais avec des réserves, se sentant plus à l\'aise uniquement avec les transactions' }, value: 50 }, { id: 'c', text: { es: 'Declinar porque "ese no es mi trabajo, para eso están los asesores"', en: 'Decline because "that\'s not my job, that\'s what advisors are for"', fr: 'Refuser car « ce n\'est pas mon travail, c\'est pour cela qu\'il y a des conseillers »' }, value: 0 }, { id: 'd', text: { es: 'Pedir un aumento de salario antes de aceptar responsabilidades adicionales', en: 'Ask for a raise before accepting additional responsibilities', fr: 'Demander une augmentation de salaire avant d\'accepter des responsabilités supplémentaires' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'bank-bt-rd-3', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-automation', type: 'scale', content: { es: '¿Qué tan cómodo se siente aprendiendo y utilizando nuevas tecnologías y sistemas bancarios?', en: 'How comfortable do you feel learning and using new technologies and banking systems?', fr: 'À quel point êtes-vous à l\'aise pour apprendre et utiliser de nouvelles technologies et systèmes bancaires ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Los cambios tecnológicos me generan ansiedad', en: 'Technological changes cause me anxiety', fr: 'Les changements technologiques me causent de l\'anxiété' }, max: { es: 'Aprendo rápido y disfruto explorar nuevas tecnologías', en: 'I learn quickly and enjoy exploring new technologies', fr: 'J\'apprends rapidement et j\'aime explorer les nouvelles technologies' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'bank-bt-rd-4', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-digital-literacy', type: 'scale', content: { es: '¿Qué tan capaz se siente de guiar a un cliente para que use la aplicación móvil del banco o la banca en línea?', en: 'How capable do you feel guiding a client to use the bank\'s mobile app or online banking?', fr: 'À quel point vous sentez-vous capable de guider un client pour utiliser l\'application mobile de la banque ou la banque en ligne ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No manejo bien las aplicaciones del banco', en: 'I don\'t handle the bank\'s applications well', fr: 'Je ne maîtrise pas bien les applications de la banque' }, max: { es: 'Domino todas las funciones y puedo guiar a cualquier cliente paso a paso', en: 'I master all functions and can guide any client step by step', fr: 'Je maîtrise toutes les fonctions et peux guider n\'importe quel client étape par étape' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'bank-bt-rd-5', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-role-evolution', type: 'scenario', content: { es: 'El banco anuncia que dentro de 12 meses todas las sucursales migrarán a un modelo "cashless" donde no habrá manejo de efectivo en ventanilla. Los depósitos y retiros de efectivo se harán exclusivamente en ATMs inteligentes y casilleros automatizados. Los cajeros serán reconvertidos a "asesores de servicio" enfocados en apertura de cuentas, venta de productos y resolución de problemas.\n\nDescriba cómo se prepararía usted personalmente para esta transición y qué habilidades necesitaría desarrollar.', en: 'The bank announces that within 12 months all branches will migrate to a "cashless" model where there will be no cash handling at the counter. Cash deposits and withdrawals will be done exclusively at smart ATMs and automated lockers. Tellers will be converted to "service advisors" focused on account opening, product sales, and problem resolution.\n\nDescribe how you would personally prepare for this transition and what skills you would need to develop.', fr: 'La banque annonce que dans 12 mois toutes les agences migreront vers un modèle « sans espèces » où il n\'y aura plus de manipulation d\'espèces au guichet. Les cajeros seront reconvertis en « conseillers de service ».\n\nDécrivez comment vous vous prépareriez personnellement pour cette transition et quelles compétences vous devriez développer.' }, rubric: { es: 'Evaluar: (1) Actitud positiva y proactiva ante el cambio, (2) Identificación realista de brechas de habilidades, (3) Plan concreto de desarrollo (productos, ventas, servicio), (4) Disposición para salir de la zona de confort, (5) Enfoque en las oportunidades vs. amenazas, (6) Visión de crecimiento profesional a largo plazo.', en: 'Evaluate: (1) Positive and proactive attitude toward change, (2) Realistic identification of skill gaps, (3) Concrete development plan (products, sales, service), (4) Willingness to leave comfort zone, (5) Focus on opportunities vs. threats, (6) Long-term professional growth vision.', fr: 'Évaluer : (1) Attitude positive et proactive face au changement, (2) Identification réaliste des lacunes de compétences, (3) Plan de développement concret, (4) Volonté de sortir de la zone de confort, (5) Focus sur les opportunités, (6) Vision de croissance professionnelle à long terme.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'bank-bt-rd-6', profileId: 'bank-teller', categoryId: 'bank-bt-readiness', competencyId: 'bank-bt-digital-literacy', type: 'open-text', content: { es: '¿Qué herramientas digitales utiliza actualmente en su vida personal y profesional? ¿Cómo cree que estas habilidades digitales le ayudarían en un entorno bancario cada vez más tecnológico?', en: 'What digital tools do you currently use in your personal and professional life? How do you think these digital skills would help you in an increasingly technological banking environment?', fr: 'Quels outils numériques utilisez-vous actuellement dans votre vie personnelle et professionnelle ? Comment pensez-vous que ces compétences numériques vous aideraient dans un environnement bancaire de plus en plus technologique ?' }, rubric: { es: 'Evaluar: (1) Variedad y sofisticación de herramientas digitales que usa, (2) Capacidad de transferir habilidades digitales personales al entorno laboral, (3) Curiosidad y apertura tecnológica, (4) Comprensión de las tendencias digitales bancarias, (5) Disposición para el aprendizaje continuo, (6) Ejemplos concretos de adaptación tecnológica.', en: 'Evaluate: (1) Variety and sophistication of digital tools used, (2) Ability to transfer personal digital skills to the work environment, (3) Technological curiosity and openness, (4) Understanding of banking digital trends, (5) Willingness for continuous learning, (6) Concrete examples of technological adaptation.', fr: 'Évaluer : (1) Variété et sophistication des outils numériques utilisés, (2) Capacité à transférer les compétences numériques personnelles à l\'environnement professionnel, (3) Curiosité et ouverture technologique, (4) Compréhension des tendances numériques bancaires, (5) Volonté d\'apprentissage continu, (6) Exemples concrets d\'adaptation technologique.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];
